/// Default keychain service-name prefix for the session token (one per
/// tenant). The matching account-name is `session_token`. The Tauri
/// shell reads this entry at startup to know the bearer token to
/// present.
const SESSION_TOKEN_ACCOUNT: &str = "session_token";

fn keychain_service_for(tenant: &str) -> String {
    format!("aberp.nav.{tenant}")
}

/// Persisted artifacts (cert PEM + key PEM + fingerprint) for the
/// loopback HTTPS listener live in `~/.aberp/serve/<tenant>/`. ADR-0007
/// ¬ßTransport names "next to the keychain material" ‚Äî for the
/// per-platform Keychain/Credential-Manager/secret-service backends
/// "next to" is the user-home convention. A future ADR can pick a
/// per-OS path if needed; for now the user-home posture works on all
/// three platforms.
fn serve_artifacts_dir(tenant: &str) -> Result<PathBuf> {
    let home = dirs_home_or_loud_fail()?;
    Ok(home.join(".aberp").join("serve").join(tenant))
}

/// We deliberately do NOT import the `dirs` crate (one more dep, one
/// more supply-chain surface). `std::env::var("HOME")` covers macOS
/// and Linux; `USERPROFILE` covers Windows. Loud-fail if neither is
/// set per CLAUDE.md rule 12.
fn dirs_home_or_loud_fail() -> Result<PathBuf> {
    if let Ok(h) = std::env::var("HOME") {
        if !h.is_empty() {
            return Ok(PathBuf::from(h));
        }
    }
    if let Ok(h) = std::env::var("USERPROFILE") {
        if !h.is_empty() {
            return Ok(PathBuf::from(h));
        }
    }
    Err(anyhow!(
        "neither HOME nor USERPROFILE is set ‚Äî cannot locate ~/.aberp/serve/<tenant>/"
    ))
}

pub fn run(args: &ServeArgs) -> Result<()> {
    let _span = tracing::info_span!(
        "serve",
        tenant = %args.tenant,
        port = args.port,
        db = %args.db.display(),
    )
    .entered();

    // PR-46Œ±.1 / session-62-fix ‚Äî explicit step-entry log emits so a
    // hang at any boot step surfaces in the SPA's loading pane (via
    // recent_logs) with a name. Pre-fix, the only operator-visible
    // emit between subprocess spawn and the cert-ready log was the
    // background-thread binary-hash completion ‚Äî which made a hung
    // foreground boot indistinguishable from a missing-handshake
    // emit. Step markers below name what step is in flight; the
    // LAST one logged before a stall is the suspect.
    tracing::info!("boot step: spawning background binary-hash compute");

    // PR-45a / session-61 ‚Äî kick off the binary-hash compute FIRST,
    // before any other boot work. On a cold-cache debug build this
    // read+hash takes 5-10s; doing it on a background OS thread lets
    // the listener bind + handshake fire while the hash is still
    // crunching. Handlers block on `BinaryHashHandle::wait` if they
    // beat the background thread to the finish line (vanishingly
    // unlikely once the SPA finishes its initial /health probe).
    let binary_hash_handle = BinaryHashHandle::start_background();

    // 1. Resolve tenant id + load session token from the keychain.
    tracing::info!("boot step: resolving tenant id");
    let tenant = TenantId::new(args.tenant.clone()).ok_or_else(|| {
        anyhow!(
            "--tenant value '{}' is empty or has a null byte",
            args.tenant
        )
    })?;
    // PR-46Œ±.1 / session-62-fix ‚Äî explicit step-entry log so a
    // macOS keychain ACL prompt blocking `entry.get_password()` is
    // visible at the operator-facing layer. The keychain re-prompts
    // any time the binary signature changes (e.g. a rebuild); the
    // prompt window may be hidden behind the Tauri window and the
    // operator can't tell what they're waiting for.
    tracing::info!(
        "boot step: reading session token from OS keychain (may prompt for keychain access)"
    );
    let session_token = {
        let _s = tracing::info_span!("serve.session_token").entered();
        load_or_create_session_token(&args.tenant)?
    };

    // PR-44Œ∂ / session-59 ‚Äî load the NAV credentials at startup so the
    // `POST /invoices/issue` mutation route can derive a per-request
    // `Actor` without paying keychain latency on every issuance. The
    // only field we stash is `login()` (non-secret); the secret bytes
    // are dropped when this scope exits.
    //
    // PR-46Œ± / session-62 ‚Äî pre-PR-46Œ± a missing keychain entry exited
    // the backend non-zero, which made the desktop window flash blank
    // (post-PR-45a: the Tauri shell rendered an unrecoverable Failed
    // pane). Now: a `KeychainItemMissing` variant transitions the
    // backend into the `NeedsSetup` boot state ‚Äî the listener still
    // binds, the handshake still fires (with `state=needs-setup`
    // suffix), and the new `POST /api/setup-nav-credentials` route
    // lets the SPA's first-run wizard populate the four artifacts
    // without any terminal interaction. Every OTHER credential failure
    // (locked keychain, permission denied, etc.) still loud-fails per
    // CLAUDE.md rule 12 ‚Äî those are operator-triage situations, not
    // first-run setup situations.
    // PR-46Œ±.1 / session-62-fix ‚Äî same prompt-warning posture as the
    // session_token step above. PR-57 / session-77: the four NAV
    // artifacts now live in ONE keychain item (`nav_credentials_blob`),
    // so the boot path is ONE `get_password` call ‚Üí ONE potential ACL
    // prompt on a freshly-rebuilt binary (down from four pre-PR-57).
    // The first boot after applying PR-57 on an installation with the
    // four legacy entries still present additionally reads each of
    // those once to migrate; subsequent boots take the blob-only path.
    tracing::info!(
        "boot step: reading NAV credentials blob from OS keychain (may prompt for keychain access; \
         legacy 4-item migration on first launch after PR-57)"
    );
    let initial_boot_state = {
        let _s = tracing::info_span!("serve.nav_credentials").entered();
        match NavCredentials::load_from_keychain(&args.tenant) {
            Ok(creds) => {
                // PR-51 / session-71 ‚Äî NAV creds present; the second
                // gate is the per-tenant seller.toml. A missing or
                // identity-incomplete file transitions to
                // NeedsSellerConfig so the SPA can fire its wizard
                // INSTEAD OF letting the operator hit the route
                // surface and get a typed `missing_seller_config` 400
                // hours later.
                derive_initial_boot_state_with_seller_check(creds.login().to_string(), &args.tenant)
            }
            Err(NavTransportError::KeychainItemMissing { item, .. }) => {
                tracing::warn!(
                    item = item,
                    "NAV credential missing from OS keychain ‚Äî entering needs-setup boot state; \
                     SPA first-run wizard will populate via POST /api/setup-nav-credentials"
                );
                ServeBootState::NeedsSetup
            }
            Err(other) => {
                return Err(anyhow!(other)
                    .context("load NAV credentials from OS keychain for actor derivation"));
            }
        }
    };

    // Session-149 ‚Äî read the SMTP password into the in-process cache
    // NOW, while we are still inside the boot keychain-read burst
    // (session token ‚Üí NAV blob ‚Üí SMTP password). Doing it here means
    // the OS sees one contiguous prompt burst on a freshly-rebuilt
    // binary, so the operator's Always-Allow consolidates and no SMTP
    // prompt surprises them later (e.g. opening Maintenance ‚Üí Tenants).
    // Skips the read silently if `[seller.smtp]` is absent; never
    // hard-fails boot on a missing/locked SMTP item (see SecretsCache).
    tracing::info!(
        "boot step: reading SMTP password from OS keychain (may prompt for keychain access if \
         [seller.smtp] is configured)"
    );
    let secrets_cache = {
        let _s = tracing::info_span!("serve.smtp_password").entered();
        match setup_seller_info::seller_toml_path_for_tenant(&args.tenant) {
            Ok(path) => SecretsCache::init_at_boot(&args.tenant, &path),
            Err(e) => {
                tracing::warn!(
                    error = %format!("{e:#}"),
                    "could not resolve seller.toml path at boot ‚Äî SMTP password cache left empty"
                );
                SecretsCache::empty()
            }
        }
    };

    // PR-73a / hotfix ‚Äî run the idempotent billing schema migrations
    // at boot so an existing pre-PR-73 tenant DB picks up the five
    // `bank_account_*` columns on `invoice` before the first
    // `list_invoices` request runs `load_invoice_bank_snapshot_in_tx`.
    // Pre-PR-73a the migration only ran lazily inside the issue path's
    // `pre_tx_setup` (issue_invoice / issue_storno / issue_modification);
    // a read-only operator who opened the SPA without issuing first hit
    // a 500 from the bank-snapshot SELECT against the un-migrated
    // schema. `ADD COLUMN IF NOT EXISTS` is idempotent so re-running on
    // every boot costs nothing on already-migrated DBs.
    tracing::info!("boot step: ensuring billing schema (idempotent migrations)");
    {
        let _s = tracing::info_span!("serve.ensure_billing_schema").entered();
        if let Some(parent) = args.db.parent() {
            std::fs::create_dir_all(parent).with_context(|| {
                format!(
                    "create parent directory {} for tenant DuckDB",
                    parent.display()
                )
            })?;
        }
        let mut billing_store = DuckDbBillingStore::open(&args.db).with_context(|| {
            format!(
                "open billing DuckDB at {} for boot migration",
                args.db.display()
            )
        })?;
        billing_store
            .ensure_schema()
            .context("ensure billing schema at serve boot")?;
    }

    // PR-91 ‚Äî pin the products table schema at boot for the same
    // read-only-cold-start reason as the partners + billing tables
    // (PR-73a). Idempotent CREATE TABLE IF NOT EXISTS so re-runs on
    // already-migrated DBs cost nothing.
    {
        let _s = tracing::info_span!("serve.ensure_products_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for products boot migration",
                args.db.display()
            )
        })?;
        products::ensure_schema(&conn).context("ensure products schema at serve boot")?;
    }

    // Session 152b ‚Äî reconcile the audit-ledger mirror against the DB
    // at boot. The mirror (`<db>.audit.log`) is a derivable cache, not
    // a source of truth. If the operator nuked the DuckDB per the
    // dev-DB-disposable rule but left the mirror in place, the mirror
    // is now AHEAD of the fresh DB; pre-152b the first post-commit
    // `sync_mirror` 500'd ("mirror is ahead of DB"), skipping the NAV
    // XML write and cascading into a submit 500. Boot reconciliation
    // truncates the ahead mirror back to the DB's max seq (and handles
    // missing / behind / corrupt / hash-mismatch). Idempotent on a
    // healthy state. Per-write `sync_mirror` still loud-fails on
    // mid-process divergence ‚Äî that IS a runtime bug.
    tracing::info!("boot step: reconciling audit-ledger mirror with DB (idempotent recovery)");
    {
        let _s = tracing::info_span!("serve.recover_audit_mirror").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for audit-ledger mirror recovery",
                args.db.display()
            )
        })?;
        aberp_audit_ledger::ensure_schema(&conn)
            .context("ensure audit-ledger schema at serve boot")?;
        let mirror_path = aberp_audit_ledger::mirror_path_for(&args.db);
        let action = aberp_audit_ledger::ensure_consistent_with_db(&conn, &mirror_path)
            .context("reconcile audit-ledger mirror with DB at serve boot")?;
        tracing::info!(?action, "audit-ledger mirror reconciled at boot");
    }

    // 2. Resolve / generate the loopback cert + key.
    tracing::info!("boot step: preparing serve-artifacts directory");
    let artifacts_dir = serve_artifacts_dir(&args.tenant)?;
    std::fs::create_dir_all(&artifacts_dir).with_context(|| {
        format!(
            "create serve artifacts directory at {}",
            artifacts_dir.display()
        )
    })?;
    let cert_path = artifacts_dir.join("loopback.crt.pem");
    let key_path = artifacts_dir.join("loopback.key.pem");
    let fingerprint_path = artifacts_dir.join("loopback.fingerprint.sha256");
    tracing::info!("boot step: ensuring loopback TLS cert + key (rcgen on first launch)");
    let (cert_pem, key_pem, fingerprint_hex) = {
        let _s = tracing::info_span!("serve.loopback_cert").entered();
        ensure_loopback_cert(&cert_path, &key_path, &fingerprint_path)?
    };
    tracing::info!(
        cert = %cert_path.display(),
        fingerprint = %fingerprint_hex,
        "loopback TLS certificate ready"
    );

    // 3. Build the rustls server config.
    tracing::info!("boot step: building rustls server config");
    let rustls_config = {
        let _s = tracing::info_span!("serve.rustls_config").entered();
        build_rustls_config(&cert_pem, &key_pem)?
    };

    // 4. Build the shared application state. `binary_hash` is the
    //    handle to the background compute kicked off at the top;
    //    handlers block on it if they need the hash before it
    //    resolves.
    //
    // PR-46Œ± / session-62 ‚Äî `boot_state` carries the (possibly
    // mutable) Ready / NeedsSetup discriminator. The setup route
    // takes the write lock when transitioning; every other handler
    // takes a read lock to either pull `operator_login` or reject
    // with 503 needs-setup.
    let state_token_at_print = initial_boot_state.state_token();
    let state = AppState {
        db_path: Arc::new(args.db.clone()),
        tenant,
        binary_hash: binary_hash_handle,
        session_token: Arc::new(session_token.clone()),
        boot_state: Arc::new(std::sync::RwLock::new(initial_boot_state)),
        secrets_cache,
    };

    // 5. Build the axum router.
    let app = build_router(state);

    // 6. Build a tokio multi-thread runtime (the serve subcommand is
    //    long-running on a single operator workstation; a small
    //    worker pool is fine here).
    tracing::info!("boot step: building tokio multi-thread runtime");
    let runtime = {
        let _s = tracing::info_span!("serve.tokio_runtime").entered();
        tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .context("build tokio multi-thread runtime for axum")?
    };

    // 7. Bind the TCP listener synchronously so we can read the
    //    kernel-assigned port BEFORE printing the handshake. Pre-
    //    PR-45a we passed `127.0.0.1:0` straight to `bind_rustls`,
    //    which made the handshake unparseable: the operator-visible
    //    line read `https://127.0.0.1:0/`, and the desktop shell's
    //    handshake parser had no way to learn the resolved port.
    tracing::info!(port = args.port, "boot step: binding loopback TCP listener");
    let bind_addr: SocketAddr = format!("127.0.0.1:{}", args.port)
        .parse()
        .with_context(|| {
            format!(
                "parse loopback socket address 127.0.0.1:{} (port out of range?)",
                args.port
            )
        })?;
    let listener = {
        let _s = tracing::info_span!("serve.tcp_bind").entered();
        TcpListener::bind(bind_addr).with_context(|| format!("bind TCP listener at {bind_addr}"))?
    };
    let resolved_addr = listener
        .local_addr()
        .context("read resolved local_addr from TCP listener")?;
    tracing::info!(
        bind = %resolved_addr,
        fingerprint = %fingerprint_hex,
        session_token_first8 = &session_token[..8.min(session_token.len())],
        "starting HTTPS loopback listener ‚Äî present \
         `Authorization: Bearer <session_token>` to authenticated routes; \
         verify TLS cert against the SHA-256 fingerprint"
    );

    // PR-45a / session-61 ‚Äî machine-parseable handshake line. The
    // Tauri shell's `handshake::parse` consumes the line as
    // whitespace-separated tokens (literal `READY`, a `SocketAddr`,
    // `sha256:<64-hex>`, and PR-46Œ±-added optional `state=<token>`);
    // the addr token round-trips through `parse::<SocketAddr>()`
    // cleanly. The human-readable `aberp serve: ‚Ä¶` line moved to the
    // tracing log above so an operator running the shell still sees
    // the resolved port in the forwarded stderr stream. A drift in
    // either side fails loudly at the SPA's handshake step rather
    // than silently mis-routing.
    //
    // PR-46Œ± / session-62 ‚Äî the trailing `state=<token>` token
    // exposes the boot lifecycle (Ready vs NeedsSetup) at the
    // handshake boundary so the Tauri shell can dispatch the SPA's
    // first-paint between the normal app and the first-run setup
    // wizard. Token values: `ready` | `needs-setup`. Missing token =
    // `ready` (backwards-compat with the PR-45a line shape for any
    // future-stable third-party reader; the parser tolerates absence).
    println!(
        "READY {} sha256:{} state={}",
        resolved_addr, fingerprint_hex, state_token_at_print
    );

    runtime.block_on(async move {
        let config = RustlsConfig::from_der(rustls_config.0, rustls_config.1)
            .await
            .context("build axum-server RustlsConfig")?;
        axum_server::from_tcp_rustls(listener, config)
            .serve(app.into_make_service())
            .await
            .context("axum_server::from_tcp_rustls(...).serve(...)")
    })?;

    Ok(())
}

// ‚îÄ‚îÄ Cert / key / fingerprint persistence ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

/// If the persisted artifacts already exist, read them. Otherwise
/// generate a fresh self-signed cert via `rcgen`, persist all three
/// artifacts (cert PEM, key PEM, hex fingerprint), and return them.
///
/// Returns the *PEM bytes* of cert and key (string-ish) and the hex
/// fingerprint string.
fn ensure_loopback_cert(
    cert_path: &Path,
    key_path: &Path,
    fingerprint_path: &Path,
) -> Result<(String, String, String)> {
    if cert_path.exists() && key_path.exists() {
        let cert_pem = std::fs::read_to_string(cert_path)
            .with_context(|| format!("read persisted cert PEM from {}", cert_path.display()))?;
        let key_pem = std::fs::read_to_string(key_path)
            .with_context(|| format!("read persisted key PEM from {}", key_path.display()))?;
        let fingerprint = compute_cert_fingerprint(&cert_pem)?;
        // Re-persist the fingerprint file even if it already exists ‚Äî
        // a missing fingerprint file would otherwise be a confusing
        // first-startup-after-corrupted-state failure mode.
        std::fs::write(fingerprint_path, &fingerprint).with_context(|| {
            format!(
                "write loopback fingerprint to {}",
                fingerprint_path.display()
            )
        })?;
        return Ok((cert_pem, key_pem, fingerprint));
    }

    // Generate fresh.
    let mut params = rcgen::CertificateParams::new(vec!["localhost".to_string()])
        .context("rcgen CertificateParams::new")?;
    let mut dn = DistinguishedName::new();
    dn.push(rcgen::DnType::CommonName, "ABERP loopback");
    params.distinguished_name = dn;
    params.key_usages = vec![
        KeyUsagePurpose::DigitalSignature,
        KeyUsagePurpose::KeyEncipherment,
    ];
    let key_pair = KeyPair::generate().context("rcgen KeyPair::generate")?;
    let cert = params
        .self_signed(&key_pair)
        .context("rcgen CertificateParams::self_signed")?;

    let cert_pem = cert.pem();
    let key_pem = key_pair.serialize_pem();
    let fingerprint = compute_cert_fingerprint(&cert_pem)?;

    std::fs::write(cert_path, &cert_pem)
        .with_context(|| format!("write loopback cert PEM to {}", cert_path.display()))?;
    std::fs::write(key_path, &key_pem)
        .with_context(|| format!("write loopback key PEM to {}", key_path.display()))?;
    std::fs::write(fingerprint_path, &fingerprint).with_context(|| {
        format!(
            "write loopback fingerprint to {}",
            fingerprint_path.display()
        )
    })?;

    // Tighten the key file's permissions on POSIX. On Windows the call
    // is a no-op; we silently skip it.
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let mut perms = std::fs::metadata(key_path)
            .with_context(|| format!("stat {}", key_path.display()))?
            .permissions();
        perms.set_mode(0o600);
        std::fs::set_permissions(key_path, perms)
            .with_context(|| format!("chmod 0600 {}", key_path.display()))?;
    }

    Ok((cert_pem, key_pem, fingerprint))
}

/// SHA-256 fingerprint of the **DER body** of the first cert in a PEM
/// bundle, hex-encoded. Matches the format `openssl x509 -fingerprint
/// -sha256 -noout -in cert.pem` produces (lower-case, no colons).
fn compute_cert_fingerprint(cert_pem: &str) -> Result<String> {
    let mut bytes = cert_pem.as_bytes();
    let cert_der = rustls_pemfile::certs(&mut bytes)
        .next()
        .ok_or_else(|| anyhow!("no certificate found in PEM bundle"))?
        .context("parse certificate PEM")?;
    let mut hasher = Sha256::new();
    hasher.update(&cert_der);
    Ok(hex::encode(hasher.finalize()))
}

/// Parse the PEM bytes into the `Vec<u8>` DER pair `axum_server`'s
/// `RustlsConfig::from_der` wants.
fn build_rustls_config(cert_pem: &str, key_pem: &str) -> Result<(Vec<Vec<u8>>, Vec<u8>)> {
    let mut cert_bytes = cert_pem.as_bytes();
    let certs: Vec<Vec<u8>> = rustls_pemfile::certs(&mut cert_bytes)
        .map(|c| c.map(|der| der.to_vec()))
        .collect::<Result<Vec<_>, _>>()
        .context("parse loopback cert PEM")?;
    if certs.is_empty() {
        return Err(anyhow!("loopback cert PEM contained no certificates"));
    }
    let mut key_bytes = key_pem.as_bytes();
    let key = rustls_pemfile::private_key(&mut key_bytes)
        .context("parse loopback key PEM")?
        .ok_or_else(|| anyhow!("loopback key PEM contained no private key"))?;
    Ok((certs, key.secret_der().to_vec()))
}

// ‚îÄ‚îÄ Session token in the OS keychain ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

/// Look up the session token in the OS keychain for this tenant; if
/// absent, generate a fresh 256-bit random token (hex-encoded) and
/// persist it.
fn load_or_create_session_token(tenant: &str) -> Result<String> {
    let service = keychain_service_for(tenant);
    let entry = keyring::Entry::new(&service, SESSION_TOKEN_ACCOUNT)
        .context("build keyring::Entry for session token")?;
    match entry.get_password() {
        Ok(existing) if !existing.is_empty() => Ok(existing),
        Ok(_) | Err(keyring::Error::NoEntry) => {
            let fresh = generate_session_token();
            entry
                .set_password(&fresh)
                .context("write fresh session token to OS keychain")?;
            tracing::info!(
                tenant = tenant,
                "minted fresh session token in OS keychain (account `session_token`)"
            );
            Ok(fresh)
        }
        Err(e) => Err(anyhow!("keychain access for session token failed: {e}")),
    }
}

/// 32 random bytes from the OS RNG, hex-encoded. We do not pull in
/// `rand` for this ‚Äî `std::time::SystemTime::now()` is the cheap
/// source for one-shot key material on a single workstation, mixed
/// with a per-process ULID. A proper rotation flow with a real RNG
/// can land when the operator-action surface needs it; for the first
/// MVP token a 256-bit value derived from system entropy is
/// sufficient.
///
/// Per CLAUDE.md rule 12, we name the trade-off loud: this is NOT a
/// cryptographic key. It is a single-workstation bearer secret that
/// gates one local HTTPS endpoint behind the OS-keychain trust
/// boundary the rest of ABERP already lives behind. A future
/// PR-9-1.5 (or session 12) can swap this for a `rand`-sourced
/// equivalent.
fn generate_session_token() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now_nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0u128);
    let ulid_bytes = ulid::Ulid::new().to_bytes();
    let pid = std::process::id();
    let mut hasher = Sha256::new();
    hasher.update(now_nanos.to_le_bytes());
    hasher.update(ulid_bytes);
    hasher.update(pid.to_le_bytes());
    hex::encode(hasher.finalize())
}

// ‚îÄ‚îÄ Axum router + handlers ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

/// PR-46Œ± / session-62 ‚Äî boot lifecycle discriminator on the
/// [`AppState`]. `NeedsSetup` means the keychain is empty for this
/// tenant; the listener still binds + the handshake still fires so the
/// Tauri shell + SPA can render a first-run setup wizard against the
/// loopback. `Ready` carries the operator-login string the audit-
/// ledger actor derivation needs (mirrors the pre-PR-46Œ±
/// `Arc<String>` shape).
///
/// Single-tenant scope per the brief: the boot-state is one bit of
/// in-process state shared between the setup route (which writes when
/// transitioning) and every other route (which reads to either pull
/// the login OR reject with 503). Multi-tenant CRUD lifts this to a
/// per-tenant registry in a later PR-46Œ≤.
///
/// PR-51 / session-71 ‚Äî third variant `NeedsSellerConfig` for the
/// SPA's seller-config wizard. Detected at boot when the NAV
/// credentials load but `~/.aberp/<tenant>/seller.toml` is absent or
/// missing required identity fields. The state token
/// `needs-seller-config` rides the handshake suffix so the Tauri
/// shell's first-paint dispatch picks the right wizard without an
/// extra round-trip. `operator_login` is carried on the variant
/// because NAV creds are already loaded ‚Äî only the seller-config gate
/// remains; the same login feeds the audit actor once the wizard
/// flips the state to Ready.
#[derive(Debug, Clone)]
pub enum ServeBootState {
    /// Keychain has no NAV credentials for this tenant. The only
    /// route that responds to mutations is
    /// `POST /api/setup-nav-credentials`; every other gated route
    /// returns 503 with a typed body the SPA renders inline.
    NeedsSetup,
    /// PR-51 / session-71 ‚Äî keychain populated, but
    /// `~/.aberp/<tenant>/seller.toml` is missing or its identity
    /// block (legal_name + tax_number + address) is incomplete. The
    /// SPA's `SellerConfigWizard` fires; `POST /api/setup-seller-info`
    /// is the only mutation route that responds (bypasses Bearer-auth
    /// for the same A170 chicken-and-egg reason as the NAV-creds
    /// wizard). Every other gated route returns 503.
    NeedsSellerConfig { operator_login: String },
    /// Keychain is populated; the per-request audit-actor login was
    /// extracted at startup (or at setup-route-transition time) and
    /// is cached here for the Actor derivation site.
    Ready { operator_login: String },
}

impl ServeBootState {
    /// String token emitted on the handshake `state=<token>` suffix
    /// (PR-46Œ±). The Tauri shell's `handshake::parse` reads it to
    /// route the SPA's first paint between the normal app and the
    /// setup wizard.
    ///
    /// PR-51 / session-71 ‚Äî added the `needs-seller-config` token for
    /// the new boot-state variant. Mirror in
    /// `apps/aberp-ui/src/handshake.rs::parse_state_value`.
    pub fn state_token(&self) -> &'static str {
        match self {
            ServeBootState::NeedsSetup => "needs-setup",
            ServeBootState::NeedsSellerConfig { .. } => "needs-seller-config",
            ServeBootState::Ready { .. } => "ready",
        }
    }

    /// `true` iff the backend is past the needs-setup gate. Used by
    /// the route precondition helper.
    pub fn is_ready(&self) -> bool {
        matches!(self, ServeBootState::Ready { .. })
    }

    /// PR-51 / session-71 ‚Äî `true` iff a setup-flow route (NAV creds
    /// OR seller info) should bypass the Bearer-auth gate. The
    /// chicken-and-egg posture from A170 (the SPA wizard runs BEFORE
    /// the operator has acquired a session token) extends to the
    /// seller-config wizard too. Used by both setup-route handlers.
    pub fn allows_setup_bypass(&self) -> bool {
        !matches!(self, ServeBootState::Ready { .. })
    }
}

/// PR-51 / session-71 ‚Äî pick the boot state to enter when NAV creds
/// load cleanly. Reads `~/.aberp/<tenant>/seller.toml` and:
///
///   - missing file OR identity-incomplete ‚Üí `NeedsSellerConfig`
///   - identity present ‚Üí `Ready`
///
/// Reads outside the `RwLock` so a slow filesystem doesn't delay the
/// listener bind; called once at boot. Errors reading the file fall
/// through to `NeedsSellerConfig` with a tracing warning ‚Äî that
/// surfaces the bad file to the operator AND lets the wizard
/// overwrite it (better than refusing to boot).
fn derive_initial_boot_state_with_seller_check(
    operator_login: String,
    tenant: &str,
) -> ServeBootState {
    match setup_seller_info::seller_toml_path_for_tenant(tenant) {
        Ok(path) => match setup_seller_info::read_seller_identity(&path) {
            Ok(Some(_id)) => {
                tracing::info!(
                    seller_toml = %path.display(),
                    "seller.toml identity block present; entering Ready boot state"
                );
                ServeBootState::Ready { operator_login }
            }
            Ok(None) => {
                tracing::warn!(
                    seller_toml = %path.display(),
                    "seller.toml missing or identity-incomplete; entering needs-seller-config boot state; \
                     SPA SellerConfigWizard will populate via POST /api/setup-seller-info"
                );
                ServeBootState::NeedsSellerConfig { operator_login }
            }
            Err(e) => {
                tracing::warn!(
                    seller_toml = %path.display(),
                    error = %format!("{e:#}"),
                    "seller.toml read failed; entering needs-seller-config boot state so the wizard can overwrite"
                );
                ServeBootState::NeedsSellerConfig { operator_login }
            }
        },
        Err(e) => {
            tracing::warn!(
                error = %format!("{e:#}"),
                "HOME env var missing; entering needs-seller-config boot state so the wizard can surface the error"
            );
            ServeBootState::NeedsSellerConfig { operator_login }
        }
    }
}

/// Per-request shared state passed to every authenticated handler.
///
/// Public surface as of PR-44Œµ.UI / session-58 so the
/// `apps/aberp/tests/serve_pdf_route.rs` integration test can
/// exercise [`get_invoice_pdf`] directly without spinning the axum
/// listener (the listener still owns the lifecycle in `run`). Fields
/// stay narrow ‚Äî the cert + fingerprint + tokio runtime stay private
/// to `run` per ADR-0007 ¬ßTransport (the SPA never sees them, and
/// neither does the read-path test surface).
///
/// PR-44Œ∂ / session-59 added `operator_login` so the new
/// `POST /invoices/issue` mutation route can derive an `Actor` per
/// request without re-loading NAV credentials from the keychain
/// (which already happened once at `run` startup). The full
/// [`NavCredentials`] is NOT stored on the state ‚Äî only the
/// non-secret `login()` value, which is the only field the audit-
/// ledger actor needs. Keeps secrets out of the route surface.
///
/// PR-46Œ± / session-62 ‚Äî `operator_login` moved inside the
/// [`ServeBootState`] enum (`Arc<RwLock<ServeBootState>>`). On a
/// fresh install with empty keychain the backend now starts in
/// `NeedsSetup`; the new `POST /api/setup-nav-credentials` route
/// flips it to `Ready` after writing the four keychain entries.
/// Every existing route checks the state via [`require_ready`] and
/// either pulls `operator_login` OR returns 503 needs-setup.
#[derive(Clone)]
pub struct AppState {
    pub db_path: Arc<PathBuf>,
    pub tenant: TenantId,
    /// PR-45a / session-61 ‚Äî handle to the background-computed binary
    /// hash. Reading a debug `aberp` binary off cold disk + hashing it
    /// took ~7.5s in `aberp serve`'s synchronous boot path, which
    /// blew the desktop shell's 10s `HANDSHAKE_TIMEOUT`. The compute
    /// now runs on a dedicated OS thread spawned at `run` entry; HTTP
    /// handlers call `binary_hash.wait()` (essentially zero-latency
    /// after a few seconds of uptime). See [`BinaryHashHandle`] for
    /// the failure-mode posture.
    pub binary_hash: BinaryHashHandle,
    pub session_token: Arc<String>,
    /// PR-46Œ± / session-62 ‚Äî boot lifecycle gate. `Ready` carries
    /// the operator-login string; `NeedsSetup` means the keychain is
    /// empty and only the setup route responds to mutations.
    pub boot_state: Arc<std::sync::RwLock<ServeBootState>>,
    /// Session-149 ‚Äî in-process secrets cache populated during the boot
    /// keychain-read burst. The SMTP password is read ONCE at boot and
    /// served from here for every post-boot consumer (Settings GET/PUT,
    /// email send, test connection), so the OS keychain is never read
    /// lazily mid-session. See [`SecretsCache`].
    pub secrets_cache: SecretsCache,
}

fn build_router(state: AppState) -> Router {
    Router::new()
        .route("/health", get(handle_health))
        .route("/invoices", get(handle_list_invoices))
        .route("/invoices/issue", post(handle_issue_invoice))
        .route("/invoices/:id", get(handle_get_invoice))
        .route("/invoices/:id/pdf", get(handle_get_invoice_pdf))
        .route("/invoices/:id/submit", post(handle_submit_invoice))
        .route("/invoices/:id/poll-ack", post(handle_poll_ack))
        .route("/api/invoices/:id/storno", post(handle_storno_invoice))
        .route(
            "/api/invoices/:id/modification",
            post(handle_modification_invoice),
        )
        .route(
            "/api/invoices/:id/issuance-input",
            get(handle_get_issuance_input),
        )
        // PR-70 / ADR-0039 ‚Äî operational "quick mark as paid" route.
        // Records a payment receipt against a Finalized invoice
        // WITHOUT changing the NAV regulatory state ladder
        // (paid-vs-unpaid is operational metadata, queried separately).
        .route(
            "/api/invoices/:id/mark-paid",
            post(handle_mark_invoice_paid),
        )
        .route("/audit/:invoice_id", get(handle_get_audit))
        // PR-46Œ± / session-62 ‚Äî first-run setup route. Accepts the
        // four NAV credential artifacts and writes them to the OS
        // keychain. In `NeedsSetup` mode it bypasses bearer-auth (the
        // SPA wizard has no other way to populate the keychain on a
        // fresh machine ‚Äî A170); once the boot state transitions to
        // `Ready` the route requires the standard Bearer-auth header
        // like every other mutation.
        .route(
            "/api/setup-nav-credentials",
            post(handle_setup_nav_credentials),
        )
        // PR-51 / session-71 ‚Äî second-run-setup route. Accepts the
        // operator-typed seller identity (legal name + tax number +
        // address) + bank info and writes it to
        // `~/.aberp/<tenant>/seller.toml` atomically. In
        // `NeedsSetup` OR `NeedsSellerConfig` mode the route
        // bypasses Bearer-auth (the SPA wizard chain has no session-
        // token bearer yet ‚Äî same A170 chicken-and-egg posture as
        // the NAV-creds wizard); once the boot state transitions to
        // `Ready` the route requires the standard Bearer-auth
        // header (so an operator can re-run the wizard from the
        // settings screen without losing auth).
        .route("/api/setup-seller-info", post(handle_setup_seller_info))
        // PR-53 / session-73 ‚Äî read-side counterparts of the two setup
        // routes, plus the single-slot rotate route. All three are
        // Ready-only + bearer-required (rotation happens after the
        // wizard chain ‚Äî A170 only applies to first-run-setup).
        .route("/api/seller-info", get(handle_get_seller_info))
        .route(
            "/api/nav-credentials-status",
            get(handle_get_nav_credentials_status),
        )
        .route(
            "/api/rotate-nav-credential",
            post(handle_rotate_nav_credential),
        )
        // PR-48Œ± / session-68 ‚Äî partner CRUD. Five routes (list +
        // create on the collection; get + update + delete on the
        // resource), all require_ready + bearer auth ‚Äî partners is a
        // Ready-state feature, not a first-run-setup surface.
        .route(
            "/api/partners",
            get(handle_list_partners).post(handle_create_partner),
        )
        .route(
            "/api/partners/:id",
            get(handle_get_partner)
                .put(handle_update_partner)
                .delete(handle_delete_partner),
        )
        // PR-91 ‚Äî products master-data CRUD. Five routes (list + create
        // on the collection; get + update + delete on the resource), all
        // require_ready + bearer auth ‚Äî products is a Ready-state
        // feature, not a first-run-setup surface. Mirrors the partners
        // route shape.
        .route(
            "/api/products",
            get(handle_list_products).post(handle_create_product),
        )
        .route(
            "/api/products/:id",
            get(handle_get_product)
                .put(handle_update_product)
                .delete(handle_delete_product),
        )
        // PR-72 / session-94 ‚Äî multi-bank-account CRUD (PR-B of the
        // multi-bank initiative; ADR-0040 ¬ßaddendum). Five routes
        // (list + create on the collection; update + delete + flip-
        // default on the resource), all require_ready + bearer auth ‚Äî
        // bank-accounts is a Ready-state feature; first-run setup goes
        // through SellerConfigWizard. The set-default flip is its own
        // route to keep the mental model crisp (mutating the default
        // is a separate intent from editing the entry's fields).
        .route(
            "/api/seller/banks",
            get(handle_list_seller_banks).post(handle_create_seller_bank),
        )
        .route(
            "/api/seller/banks/:id",
            axum::routing::put(handle_update_seller_bank).delete(handle_delete_seller_bank),
        )
        .route(
            "/api/seller/banks/:id/set-default",
            post(handle_set_default_seller_bank),
        )
        // PR-89 ‚Äî operator-configurable invoice-number template
        // (`[seller.numbering]` section of seller.toml). GET returns
        // the persisted template (or the default INV-default/00001
        // shape when absent); PUT replaces it atomically, preserving
        // every other section of seller.toml (identity + banks).
        .route(
            "/api/seller/numbering",
            get(handle_get_seller_numbering).put(handle_put_seller_numbering),
        )
        // PR-92 / ADR-0047 ‚Äî SMTP email delivery surfaces. GET returns
        // the `[seller.smtp]` config (non-secrets only) + a `password_set`
        // probe of the keychain. PUT writes the config (merge-not-replace
        // on seller.toml + optional password rotation to keychain).
        // POST /api/invoices/:id/email is the operator-clicked manual
        // send button on InvoiceDetail. All three require_ready + bearer
        // auth.
        .route(
            "/api/smtp-config",
            get(handle_get_smtp_config).put(handle_put_smtp_config),
        )
        // PR-98 ‚Äî operator-clicked "Test connection" button on the
        // TenantSettings SMTP subsection. Runs the TLS handshake +
        // AUTH + NOOP using the operator-typed config + (entered
        // password OR existing keychain entry); reports the typed
        // outcome WITHOUT sending mail and WITHOUT persisting
        // anything.
        .route("/api/seller/smtp/test", post(handle_test_smtp_connection))
        .route(
            "/api/invoices/:id/email",
            post(handle_email_invoice_to_buyer),
        )
        .with_state(state)
}

/// PR-46Œ± / session-62 ‚Äî typed response body emitted when the backend
/// is in `NeedsSetup` and a gated route is called. The SPA reads the
/// `state` field to dispatch to the first-run wizard; the human-
/// readable `message` is rendered inline so an operator inspecting
/// the route via `curl` sees a recognisable string.
fn needs_setup_response() -> Response {
    (
        StatusCode::SERVICE_UNAVAILABLE,
        Json(serde_json::json!({
            "state": "needs-setup",
            "message": "Set up NAV credentials before using this endpoint.",
        })),
    )
        .into_response()
}

/// PR-51 / session-71 ‚Äî sibling of [`needs_setup_response`] for the
/// post-NAV-creds, pre-seller-config gate. SPA reads `state` to
/// dispatch to `SellerConfigWizard` instead of `SetupWizard`.
fn needs_seller_config_response() -> Response {
    (
        StatusCode::SERVICE_UNAVAILABLE,
        Json(serde_json::json!({
            "state": "needs-seller-config",
            "message": "Save seller identity (legal name, tax number, address) before using this endpoint.",
        })),
    )
        .into_response()
}

/// PR-46Œ± / session-62 ‚Äî precondition gate for every Ready-only
/// route. Returns `Ok(operator_login)` if the backend is `Ready`;
/// returns `Err(response)` with the typed 503 needs-setup body
/// otherwise. The poison-arm guards against a panic in the setup
/// route's write transaction leaving the RwLock unusable ‚Äî that's
/// treated as a 500 (the operator-visible message points at
/// internal-state corruption, which is the truth at that point).
///
/// PR-51 / session-71 ‚Äî `NeedsSellerConfig` now exists as a third
/// state; the gate emits a distinct 503 body (`needs-seller-config`)
/// so the SPA can route the operator to the right wizard.
fn require_ready(state: &AppState) -> std::result::Result<String, Response> {
    let guard = state.boot_state.read().map_err(|e| {
        tracing::error!(error = %e, "boot_state RwLock poisoned");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(error_body("boot_state lock poisoned".to_string())),
        )
            .into_response()
    })?;
    match &*guard {
        ServeBootState::Ready { operator_login } => Ok(operator_login.clone()),
        ServeBootState::NeedsSetup => Err(needs_setup_response()),
        ServeBootState::NeedsSellerConfig { .. } => Err(needs_seller_config_response()),
    }
}

/// PR-46Œ± / session-62 ‚Äî request body for
/// `POST /api/setup-nav-credentials`. Field names are the
/// operator-readable form rather than the on-disk `ITEM_*` keychain
/// names; the SPA composer mirrors this shape.
#[derive(Debug, Deserialize)]
pub struct SetupNavCredentialsRequest {
    pub technical_user_login: String,
    pub technical_user_password: String,
    pub xml_sign_key: String,
    pub xml_change_key: String,
}

/// PR-46Œ± / session-62 ‚Äî response body for the setup route. Surfaces
/// the post-write boot state so the SPA can flip its wizard view-mode
/// to the normal app without a second probe roundtrip.
///
/// PR-51 / session-71 ‚Äî `state` widened from a single `"ready"`
/// literal to either `"ready"` or `"needs-seller-config"`. The
/// chained-wizard posture (NAV creds first ‚Üí seller config next when
/// the file is missing) means the post-success state is no longer
/// always Ready. The SPA's Tauri-shell wrapper reads this field and
/// flips its boot-state mirror to the matching variant.
#[derive(Debug, Serialize)]
struct SetupNavCredentialsResponse {
    state: &'static str,
}

/// PR-46Œ± / session-62 ‚Äî `POST /api/setup-nav-credentials` handler.
///
/// 1. Bearer-auth check ONLY if already `Ready` (chicken-and-egg
///    bypass in `NeedsSetup`; A170).
/// 2. Validate-then-write via [`setup_nav_credentials::setup_credentials_from_inputs`]
///    (the shared core both the CLI subcommand and this route go
///    through ‚Äî A167).
/// 3. Re-load NAV credentials from the now-populated keychain to
///    extract the audit-actor login.
/// 4. Take the boot_state write lock and flip
///    `NeedsSetup ‚Üí Ready { operator_login }`.
/// 5. Return 200 with `{ "state": "ready" }`. From the SPA's
///    perspective, this is the operator's exit from the wizard.
///
/// Failure modes:
///   - `400 Bad Request` ‚Äî validation failure (empty field).
///   - `401 Unauthorized` ‚Äî bearer missing in `Ready` mode.
///   - `500 Internal Server Error` ‚Äî keychain write failed OR the
///     re-load couldn't find the entries we just wrote (which would
///     indicate the OS keychain backend silently dropped a write ‚Äî
///     CLAUDE.md rule 12 surfaces it as a 500 rather than a partial-
///     success lie).
async fn handle_setup_nav_credentials(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<SetupNavCredentialsRequest>,
) -> Response {
    // Bearer check only in Ready mode. In NeedsSetup mode the operator
    // has no way to acquire a bearer (the SPA's session-token loader
    // path runs after the backend handshake, but the setup wizard
    // fires BEFORE the normal app mounts ‚Äî A170).
    let is_ready_pre_call = state
        .boot_state
        .read()
        .map(|g| g.is_ready())
        .unwrap_or(false);
    if is_ready_pre_call {
        if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
            return resp;
        }
    }

    let inputs = NavCredentialInputs {
        technical_user_login: request.technical_user_login,
        technical_user_password: request.technical_user_password,
        xml_sign_key: request.xml_sign_key,
        xml_change_key: request.xml_change_key,
    };

    match setup_nav_credentials_request(&state, &inputs) {
        Ok(next_state_token) => Json(SetupNavCredentialsResponse {
            state: next_state_token,
        })
        .into_response(),
        Err(SetupRouteHelperError::Validation(msg)) => {
            (StatusCode::BAD_REQUEST, Json(error_body(msg))).into_response()
        }
        Err(SetupRouteHelperError::Other(e)) => internal_error("setup_nav_credentials_request", e),
    }
}

/// PR-46Œ± / session-62 ‚Äî typed error from
/// [`setup_nav_credentials_request`]. The route handler maps
/// `Validation` ‚Üí 400 and `Other` ‚Üí 500 via the existing
/// [`internal_error`] helper.
#[derive(Debug)]
pub enum SetupRouteHelperError {
    Validation(String),
    Other(anyhow::Error),
}

impl From<anyhow::Error> for SetupRouteHelperError {
    fn from(e: anyhow::Error) -> Self {
        SetupRouteHelperError::Other(e)
    }
}

/// PR-46Œ± / session-62 ‚Äî library helper that backs the
/// `POST /api/setup-nav-credentials` handler. Extracted as `pub` so
/// the integration test can hit it for end-to-end pin tests without
/// spinning the HTTPS listener (same posture as `get_invoice_pdf` per
/// A158 and `issue_invoice_request` per A159 / A162 / A163).
///
/// On success: writes the four keychain entries via the shared core,
/// re-loads to extract the operator login, and flips the boot state
/// to Ready (or `NeedsSellerConfig` if the seller.toml is still
/// missing ‚Äî PR-51 / session-71 chained-wizard posture). On
/// validation failure: returns `SetupRouteHelperError::Validation`
/// (‚Üí 400). On any other error: returns
/// `SetupRouteHelperError::Other` (‚Üí 500).
///
/// Returns the `state_token` of the post-transition boot state
/// (`"ready"` or `"needs-seller-config"`) so the HTTP route layer can
/// echo it on the 200 response body ‚Äî the SPA's Tauri-shell wrapper
/// reads it to flip its mirror to the right variant without a second
/// probe.
pub fn setup_nav_credentials_request(
    state: &AppState,
    inputs: &NavCredentialInputs,
) -> std::result::Result<&'static str, SetupRouteHelperError> {
    match setup_nav_credentials::setup_credentials_from_inputs(state.tenant.as_str(), inputs) {
        Ok(()) => {}
        Err(SetupCredentialsError::Validation(msg)) => {
            return Err(SetupRouteHelperError::Validation(msg));
        }
        Err(SetupCredentialsError::Backend(e)) => {
            return Err(SetupRouteHelperError::Other(e));
        }
    }

    // Re-load to confirm the writes landed AND to extract the actor
    // login. A re-load failure here would indicate the OS keychain
    // silently dropped one of the four writes ‚Äî loud per rule 12.
    let operator_login = NavCredentials::load_from_keychain(state.tenant.as_str())
        .map_err(|e| {
            SetupRouteHelperError::Other(anyhow!(e).context(
                "setup route wrote keychain entries but re-load failed; \
                 keychain backend may have silently dropped a write",
            ))
        })?
        .login()
        .to_string();

    // Flip the boot state. The write-lock acquisition can only fail
    // on a poisoned RwLock ‚Äî same surface as `require_ready`'s poison
    // arm.
    //
    // PR-51 / session-71 ‚Äî the post-NAV-creds transition is no longer
    // unconditionally Ready. If the per-tenant seller.toml is still
    // missing the wizard chain continues with the seller-config step;
    // the SPA's next `getBootStatus` poll picks up
    // `needs-seller-config` and dispatches `SellerConfigWizard`.
    let next_state =
        derive_initial_boot_state_with_seller_check(operator_login, state.tenant.as_str());
    let next_token = next_state.state_token();
    let mut guard = state.boot_state.write().map_err(|e| {
        SetupRouteHelperError::Other(anyhow!(
            "boot_state RwLock poisoned during setup transition: {e}"
        ))
    })?;
    *guard = next_state;

    tracing::info!(
        tenant = %state.tenant.as_str(),
        next_state = next_token,
        "NAV credentials populated via setup route; boot state transitioned"
    );

    Ok(next_token)
}

