/// Route-level error wrapper distinguishing operator-facing validation
/// failure (HTTP 422) from internal IO/anyhow failures (HTTP 500).
#[derive(Debug)]
pub enum NumberingPutError {
    Validation(NumberingValidationError),
    Other(anyhow::Error),
}

impl From<anyhow::Error> for NumberingPutError {
    fn from(e: anyhow::Error) -> Self {
        NumberingPutError::Other(e)
    }
}

/// PR-89 ‚Äî library helper for the PUT route. Validates the wire body,
/// runs the domain validator, and atomically writes the new
/// `[seller.numbering]` section (preserving identity + bank sections
/// per [`numbering_mod::write_numbering_section`]). Returns the
/// validated template on success.
pub fn put_seller_numbering_request(
    state: &AppState,
    wire: NumberingTemplateWire,
    path_override: Option<&Path>,
) -> std::result::Result<NumberingTemplate, NumberingPutError> {
    let template = wire.into_domain().map_err(NumberingPutError::Validation)?;
    numbering_mod::validate_template(&template)
        .map_err(|e| NumberingPutError::Validation(NumberingValidationError::Domain(e)))?;
    let owned_path;
    let path: &Path = match path_override {
        Some(p) => p,
        None => {
            owned_path = setup_seller_info::seller_toml_path_for_tenant(state.tenant.as_str())
                .context("resolve seller.toml path for /api/seller/numbering PUT")?;
            owned_path.as_path()
        }
    };
    numbering_mod::write_numbering_section(path, &template)
        .context("write [seller.numbering] section")?;
    Ok(template)
}

// ‚îÄ‚îÄ PR-92 / ADR-0047 ‚Äî SMTP email delivery routes ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
//
// Three surfaces:
//   - GET /api/smtp-config ‚Äî returns the `[seller.smtp]` config
//     (non-secrets only) + a `password_set` bool probing the keychain.
//   - PUT /api/smtp-config ‚Äî atomically writes the config + (optionally)
//     rotates the password in the keychain. Validates the wire body
//     against `SmtpConfig::validate` (header-injection guard,
//     closed-vocab `security`).
//   - POST /api/invoices/:id/email ‚Äî the operator-clicked manual send
//     button. Looks up the buyer by tax-number ‚Üí contact_email,
//     renders + sends, writes the audit-ledger entry.
//
// The auto-send-after-issue path lives in `handle_issue_invoice` and
// calls `send_invoice_email_route` directly so the issue response can
// echo the send outcome inline.

#[derive(Debug, serde::Deserialize)]
pub struct SmtpConfigPutWire {
    pub host: String,
    pub port: u16,
    #[serde(rename = "fromAddress")]
    pub from_address: String,
    #[serde(default, rename = "fromDisplayName")]
    pub from_display_name: Option<String>,
    pub username: String,
    /// Closed-vocab token: `"StartTls"` | `"Tls"`. Plaintext is NOT
    /// in the vocab ‚Äî ADR-0047 ¬ß1.
    pub security: String,
    /// `true` to ride the NAV XML as a second attachment.
    #[serde(default, rename = "attachXml")]
    pub attach_xml: bool,
    /// Optional new password. `Some(_)` ‚Üí write to keychain; `None` ‚Üí
    /// leave the existing keychain entry untouched (so the operator
    /// can edit the host without re-typing the password).
    #[serde(default)]
    pub password: Option<String>,
}

#[derive(Debug, serde::Serialize)]
struct SmtpConfigGetResponse {
    host: String,
    port: u16,
    #[serde(rename = "fromAddress")]
    from_address: String,
    #[serde(rename = "fromDisplayName", skip_serializing_if = "Option::is_none")]
    from_display_name: Option<String>,
    username: String,
    security: String,
    #[serde(rename = "attachXml")]
    attach_xml: bool,
    /// `true` iff the keychain has a password populated for this
    /// tenant. Surfaced so the SPA can render a "password is set"
    /// indicator without ever transmitting the password back. NEVER
    /// becomes the password itself.
    #[serde(rename = "passwordSet")]
    password_set: bool,
}

#[derive(Debug, serde::Serialize)]
struct SmtpConfigGetEmpty {
    configured: bool,
    #[serde(rename = "passwordSet")]
    password_set: bool,
}

async fn handle_get_smtp_config(headers: HeaderMap, State(state): State<AppState>) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match get_smtp_config_request(&state) {
        Ok(Some(cfg)) => {
            // Session-149 ‚Äî answer from the in-process cache populated
            // at boot, NEVER probe the keychain here (this GET fires on
            // every Maintenance ‚Üí Tenants open; a lazy keychain read was
            // the source of the surprise ACL prompt).
            let password_set = state.secrets_cache.is_smtp_password_set();
            Json(SmtpConfigGetResponse {
                host: cfg.host,
                port: cfg.port,
                from_address: cfg.from_address,
                from_display_name: cfg.from_display_name,
                username: cfg.username,
                security: cfg.security.as_token().to_string(),
                attach_xml: cfg.attach_xml,
                password_set,
            })
            .into_response()
        }
        Ok(None) => {
            // Session-149 ‚Äî answer from the in-process cache populated
            // at boot, NEVER probe the keychain here (this GET fires on
            // every Maintenance ‚Üí Tenants open; a lazy keychain read was
            // the source of the surprise ACL prompt).
            let password_set = state.secrets_cache.is_smtp_password_set();
            Json(SmtpConfigGetEmpty {
                configured: false,
                password_set,
            })
            .into_response()
        }
        Err(e) => internal_error("get_smtp_config_request", e),
    }
}

/// PR-92 ‚Äî library helper for the GET route. Returns `Ok(None)` when
/// the `[seller.smtp]` section is absent (operator has not configured
/// SMTP yet). `pub` so integration tests can hit it without spinning
/// the HTTPS listener.
pub fn get_smtp_config_request(state: &AppState) -> Result<Option<SmtpConfig>> {
    let path = setup_seller_info::seller_toml_path_for_tenant(state.tenant.as_str())
        .context("resolve seller.toml path for /api/smtp-config GET")?;
    smtp_config_mod::read_smtp_config(&path)
}

#[derive(Debug)]
pub enum SmtpConfigPutError {
    Validation(Vec<smtp_config_mod::SmtpConfigValidationError>),
    BadSecurityToken(String),
    KeychainBackend(String),
    Other(anyhow::Error),
}

impl From<anyhow::Error> for SmtpConfigPutError {
    fn from(e: anyhow::Error) -> Self {
        SmtpConfigPutError::Other(e)
    }
}

async fn handle_put_smtp_config(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(wire): Json<SmtpConfigPutWire>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    match put_smtp_config_request(&state, wire) {
        Ok(cfg) => {
            // Session-149 ‚Äî answer from the in-process cache populated
            // at boot, NEVER probe the keychain here (this GET fires on
            // every Maintenance ‚Üí Tenants open; a lazy keychain read was
            // the source of the surprise ACL prompt).
            let password_set = state.secrets_cache.is_smtp_password_set();
            Json(SmtpConfigGetResponse {
                host: cfg.host,
                port: cfg.port,
                from_address: cfg.from_address,
                from_display_name: cfg.from_display_name,
                username: cfg.username,
                security: cfg.security.as_token().to_string(),
                attach_xml: cfg.attach_xml,
                password_set,
            })
            .into_response()
        }
        Err(SmtpConfigPutError::Validation(errs)) => {
            (StatusCode::UNPROCESSABLE_ENTITY, Json(errs)).into_response()
        }
        Err(SmtpConfigPutError::BadSecurityToken(msg)) => {
            (StatusCode::UNPROCESSABLE_ENTITY, msg).into_response()
        }
        Err(SmtpConfigPutError::KeychainBackend(msg)) => {
            (StatusCode::INTERNAL_SERVER_ERROR, msg).into_response()
        }
        Err(SmtpConfigPutError::Other(e)) => internal_error("put_smtp_config_request", e),
    }
}

/// PR-92 ‚Äî library helper for the PUT route. Validates the wire body,
/// writes the `[seller.smtp]` section (merge-not-replace), AND
/// optionally rotates the password in the keychain.
pub fn put_smtp_config_request(
    state: &AppState,
    wire: SmtpConfigPutWire,
) -> std::result::Result<SmtpConfig, SmtpConfigPutError> {
    let security =
        SmtpSecurity::from_token(&wire.security).map_err(SmtpConfigPutError::BadSecurityToken)?;
    let cfg = SmtpConfig {
        host: wire.host,
        port: wire.port,
        from_address: wire.from_address,
        from_display_name: wire.from_display_name,
        username: wire.username,
        security,
        attach_xml: wire.attach_xml,
    };
    cfg.validate().map_err(SmtpConfigPutError::Validation)?;
    let path = setup_seller_info::seller_toml_path_for_tenant(state.tenant.as_str())
        .context("resolve seller.toml path for /api/smtp-config PUT")?;
    smtp_config_mod::write_smtp_section(&path, &cfg).context("write [seller.smtp] section")?;
    if let Some(password) = wire.password {
        if !password.is_empty() {
            // Operator-initiated WRITE ‚Äî stays on the keychain (Part D).
            smtp_credentials::write_password(state.tenant.as_str(), &password).map_err(|e| {
                SmtpConfigPutError::KeychainBackend(format!(
                    "rotate SMTP password in keychain: {e}"
                ))
            })?;
            // Session-149 ‚Äî refresh the in-process cache so subsequent
            // reads (email send, test connection, the passwordSet flag)
            // see the new value WITHOUT re-reading the keychain.
            state
                .secrets_cache
                .refresh_smtp_password_after_write(zeroize::Zeroizing::new(password));
        }
    }
    Ok(cfg)
}

// ‚îÄ‚îÄ POST /api/seller/smtp/test ‚Äî PR-98 ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
//
// Operator-clicked "Test connection" button on TenantSettings ‚Üí
// SMTP subsection. Runs the TLS handshake + AUTH + NOOP using the
// operator-typed config + (entered password OR existing keychain
// entry). Reports the typed outcome WITHOUT sending mail and WITHOUT
// persisting anything.

#[derive(Debug, serde::Serialize)]
struct SmtpTestOutcome {
    /// `"succeeded"` | `"failed"` ‚Äî closed vocab mirroring
    /// [`EmailRouteOutcomeBody`].
    outcome: &'static str,
    /// `null` on success; closed-vocab class on failure (same
    /// taxonomy as `EmailRouteOutcomeBody::error_class`).
    #[serde(skip_serializing_if = "Option::is_none")]
    error_class: Option<&'static str>,
    /// Operator-readable detail. Scrubbed of secrets.
    #[serde(skip_serializing_if = "Option::is_none")]
    error_detail: Option<String>,
}

async fn handle_test_smtp_connection(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(wire): Json<SmtpConfigPutWire>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    // Build the typed config off the wire body ‚Äî same path the PUT
    // handler uses minus the persistence. Bad security token surfaces
    // a 422; validation errors surface a 422 with the typed body.
    let security = match smtp_config_mod::SmtpSecurity::from_token(&wire.security) {
        Ok(s) => s,
        Err(msg) => {
            return (StatusCode::UNPROCESSABLE_ENTITY, msg).into_response();
        }
    };
    let cfg = smtp_config_mod::SmtpConfig {
        host: wire.host,
        port: wire.port,
        from_address: wire.from_address,
        from_display_name: wire.from_display_name,
        username: wire.username,
        security,
        attach_xml: wire.attach_xml,
    };
    if let Err(errs) = cfg.validate() {
        return (StatusCode::UNPROCESSABLE_ENTITY, Json(errs)).into_response();
    }
    // Password: operator may have typed a new one (test that), or
    // left blank (test the existing keychain entry ‚Äî same posture as
    // the PUT body's null-leaves-untouched semantics).
    // Session-149 ‚Äî when the operator leaves the password blank, test
    // the existing password from the in-process cache (populated at
    // boot / refreshed on the last PUT). NEVER re-read the keychain
    // here ‚Äî that lazy read was a source of the surprise ACL prompt.
    let password: zeroize::Zeroizing<String> = match wire.password.as_deref() {
        Some(p) if !p.is_empty() => zeroize::Zeroizing::new(p.to_string()),
        _ => match state.secrets_cache.smtp_password() {
            Some(p) => p,
            None => {
                let body = SmtpTestOutcome {
                    outcome: "failed",
                    error_class: Some("auth"),
                    error_detail: Some(
                        "no password entered AND no existing SMTP password set".to_string(),
                    ),
                };
                return (StatusCode::OK, Json(body)).into_response();
            }
        },
    };
    match email_invoice::test_smtp_connection(&cfg, &password).await {
        Ok(()) => Json(SmtpTestOutcome {
            outcome: "succeeded",
            error_class: None,
            error_detail: None,
        })
        .into_response(),
        Err(e) => {
            let body = SmtpTestOutcome {
                outcome: "failed",
                error_class: Some(e.error_class()),
                error_detail: Some(e.scrubbed_detail()),
            };
            (StatusCode::OK, Json(body)).into_response()
        }
    }
}

/// PR-92 ‚Äî POST /api/invoices/:id/email handler. Operator-clicked
/// manual send button on InvoiceDetail. Always-writes an audit-ledger
/// entry (success OR failure) so the operator-twin record never has
/// gaps.
async fn handle_email_invoice_to_buyer(
    headers: HeaderMap,
    State(state): State<AppState>,
    AxumPath(invoice_id): AxumPath<String>,
) -> Response {
    let operator_login = match require_ready(&state) {
        Ok(login) => login,
        Err(resp) => return resp,
    };
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    // Resolve the customer tax_number by reading the side-stored
    // input.json (PR-47Œ±) ‚Äî that's the operator-typed source of
    // truth, distinct from the partner table (which may have been
    // edited post-issuance). The send path looks up the partner by
    // tax_number to get the current contact_email.
    let customer_tax_number = match resolve_customer_tax_number(&state, &invoice_id) {
        Ok(tn) => tn,
        Err(e) => {
            tracing::warn!(invoice_id = %invoice_id, error = %e, "resolve customer tax_number for email");
            return (
                StatusCode::NOT_FOUND,
                Json(error_body(format!(
                    "invoice {invoice_id} not found or has no side-stored input.json: {e:#}"
                ))),
            )
                .into_response();
        }
    };
    // Look up the invoice's number for the subject + filename. We
    // could re-derive but easier to render the PDF (it gives us the
    // number for free); the send path renders the PDF anyway.
    let invoice_number = match get_invoice_pdf(&state, &invoice_id, None) {
        Ok(Some(rendered)) => rendered.invoice_number,
        Ok(None) => {
            return (
                StatusCode::NOT_FOUND,
                Json(error_body(format!(
                    "invoice {invoice_id} not found in audit ledger"
                ))),
            )
                .into_response();
        }
        Err(e) => return internal_error("get_invoice_pdf for email", e),
    };
    let body = send_invoice_email_route(
        &state,
        &invoice_id,
        &invoice_number,
        &customer_tax_number,
        &operator_login,
        SendTrigger::Manual,
    )
    .await;
    let status = if body.outcome == "succeeded" {
        StatusCode::OK
    } else {
        match body.error_class.as_deref() {
            Some("recipient_rejected") => StatusCode::BAD_REQUEST,
            Some("auth") | Some("compose") => StatusCode::SERVICE_UNAVAILABLE,
            _ => StatusCode::BAD_GATEWAY,
        }
    };
    (status, Json(body)).into_response()
}

/// PR-92 ‚Äî shared send-and-audit path. Used by both the
/// auto-send-after-issue branch in `handle_issue_invoice` AND the
/// manual `POST /api/invoices/:id/email` handler. Always writes the
/// audit-ledger `InvoiceEmailedSent` entry (success OR failure) so
/// the operator-twin record never has gaps.
pub async fn send_invoice_email_route(
    state: &AppState,
    invoice_id: &str,
    invoice_number: &str,
    customer_tax_number: &str,
    operator_login: &str,
    trigger: SendTrigger,
) -> EmailRouteOutcomeBody {
    // Resolve the buyer's contact email from the partners table.
    let recipient_lookup =
        resolve_recipient_email(state, customer_tax_number).unwrap_or_else(|e| {
            tracing::warn!(invoice_id = %invoice_id, error = %e, "resolve_recipient_email");
            None
        });
    let (recipient_email, recipient_display_name) = match recipient_lookup {
        Some((email, name)) if !email.trim().is_empty() => (email, name),
        _ => {
            // MissingRecipient ‚Äî write audit entry, return the body.
            return finalize_email_audit(
                state,
                invoice_id,
                operator_login,
                trigger,
                Err(EmailSendError::MissingRecipient {
                    invoice_id: invoice_id.to_string(),
                }),
                String::new(),
                "(no recipient)".to_string(),
                false,
            );
        }
    };
    // Resolve seller.toml path + supplier legal name for the body
    // greeting.
    let seller_toml_path =
        match setup_seller_info::seller_toml_path_for_tenant(state.tenant.as_str()) {
            Ok(p) => p,
            Err(e) => {
                return finalize_email_audit(
                    state,
                    invoice_id,
                    operator_login,
                    trigger,
                    Err(EmailSendError::SmtpNotConfigured(format!("{e:#}"))),
                    recipient_email,
                    String::new(),
                    false,
                );
            }
        };
    let supplier_legal_name = supplier_from_seller_toml(state.tenant.as_str())
        .map(|s| s.name)
        .unwrap_or_else(|_| "ABERP".to_string());
    // Load SMTP config (from disk) + the password from the boot-
    // populated in-process cache (session-149 ‚Äî no keychain read here).
    let (cfg, password) = match email_invoice::load_smtp_credentials(
        state.secrets_cache.smtp_password(),
        &seller_toml_path,
    ) {
        Ok(t) => t,
        Err(e) => {
            return finalize_email_audit(
                state,
                invoice_id,
                operator_login,
                trigger,
                Err(e),
                recipient_email,
                String::new(),
                false,
            );
        }
    };
    // Resolve XML attachment path iff attach_xml is on.
    let xml_path_buf = if cfg.attach_xml {
        resolve_invoice_xml_path(state, invoice_id).ok()
    } else {
        None
    };
    let input = SendInvoiceEmailInput {
        invoice_id,
        tenant: state.tenant.as_str(),
        db_path: state.db_path.as_path(),
        seller_toml_path: &seller_toml_path,
        recipient_email: &recipient_email,
        recipient_display_name: recipient_display_name.as_deref(),
        invoice_number,
        supplier_legal_name: &supplier_legal_name,
        trigger,
        xml_path_if_attached: xml_path_buf.as_deref(),
    };
    let send_result = email_invoice::send_invoice_email(input, &cfg, &password).await;
    let (subject, attached_xml) = match &send_result {
        Ok(o) => (o.subject.clone(), o.attached_xml),
        Err(_) => (
            format!("Sz√°mla / Invoice {invoice_number}"),
            cfg.attach_xml && xml_path_buf.is_some(),
        ),
    };
    finalize_email_audit(
        state,
        invoice_id,
        operator_login,
        trigger,
        send_result.map(|_| ()),
        recipient_email,
        subject,
        attached_xml,
    )
}

fn finalize_email_audit(
    state: &AppState,
    invoice_id: &str,
    operator_login: &str,
    trigger: SendTrigger,
    outcome: Result<(), EmailSendError>,
    recipient: String,
    subject: String,
    attached_xml: bool,
) -> EmailRouteOutcomeBody {
    let idempotency_key = email_invoice::fresh_send_idempotency_key();
    let binary_hash_bytes = match email_invoice::binary_hash_for_audit() {
        Ok(b) => b,
        Err(e) => {
            tracing::error!(error = ?e, "compute binary hash for email audit append");
            // Still emit a body to the SPA even though the audit
            // write failed ‚Äî surfaces as a logged error.
            return match outcome {
                Ok(()) => EmailRouteOutcomeBody {
                    outcome: "succeeded".to_string(),
                    recipient,
                    error_class: None,
                    error_detail: Some(format!("(audit write failed: {e:#})")),
                    auto: trigger.is_auto(),
                    attached_xml,
                },
                Err(e) => EmailRouteOutcomeBody {
                    outcome: "failed".to_string(),
                    recipient,
                    error_class: Some(e.error_class().to_string()),
                    error_detail: Some(e.scrubbed_detail()),
                    auto: trigger.is_auto(),
                    attached_xml,
                },
            };
        }
    };
    let actor = Actor::from_local_cli(Ulid::new().to_string(), operator_login);
    let (payload, body) = match outcome {
        Ok(()) => {
            let payload = InvoiceEmailedSentPayload::succeeded(
                invoice_id,
                idempotency_key,
                &recipient,
                &subject,
                trigger.is_auto(),
                attached_xml,
            );
            let body = EmailRouteOutcomeBody {
                outcome: "succeeded".to_string(),
                recipient: recipient.clone(),
                error_class: None,
                error_detail: None,
                auto: trigger.is_auto(),
                attached_xml,
            };
            (payload, body)
        }
        Err(e) => {
            let class = e.error_class().to_string();
            let detail = e.scrubbed_detail();
            let payload = InvoiceEmailedSentPayload::failed(
                invoice_id,
                idempotency_key,
                &recipient,
                &subject,
                trigger.is_auto(),
                attached_xml,
                &class,
                &detail,
            );
            let body = EmailRouteOutcomeBody {
                outcome: "failed".to_string(),
                recipient: recipient.clone(),
                error_class: Some(class),
                error_detail: Some(detail),
                auto: trigger.is_auto(),
                attached_xml,
            };
            (payload, body)
        }
    };
    let mut body = body;
    if let Err(e) = email_invoice::record_email_audit_entry(
        state.db_path.as_path(),
        state.tenant.clone(),
        binary_hash_bytes,
        actor,
        invoice_id,
        payload,
    ) {
        tracing::error!(
            invoice_id = %invoice_id,
            error = ?e,
            "write InvoiceEmailedSent audit entry failed (the email outcome is still reported to the SPA)"
        );
        // PR-93 ‚Äî surface the audit-write failure to the SPA's banner
        // so the operator sees that the operator-twin record has a gap
        // for THIS send. The body's `outcome` already reflects the
        // SMTP result; we extend `error_detail` with an audit-write
        // marker. (CLAUDE.md rule 12 ‚Äî fail loud, not silent.)
        let marker = format!("(audit-write failed: {e:#})");
        body.error_detail = Some(match body.error_detail {
            Some(prev) => format!("{prev} {marker}"),
            None => marker,
        });
    }
    body
}

/// Resolve the buyer's contact email by reading the side-stored
/// input.json (PR-47Œ±) for the invoice's tax number, then looking up
/// the partner record. Returns `Ok(Some((email, display_name)))` on
/// hit, `Ok(None)` when no partner matches or the partner has no
/// email. `Err` for I/O / parse failures.
fn resolve_recipient_email(
    state: &AppState,
    customer_tax_number: &str,
) -> Result<Option<(String, Option<String>)>> {
    let conn = Connection::open(&*state.db_path)
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let p = match partners::find_partner_by_tax_number(
        &conn,
        state.tenant.as_str(),
        customer_tax_number,
    )? {
        Some(p) => p,
        None => return Ok(None),
    };
    let email = match p.contact_email.as_deref() {
        Some(s) if !s.trim().is_empty() => s.to_string(),
        _ => return Ok(None),
    };
    Ok(Some((email, Some(p.display_name))))
}

/// Look up the side-stored input.json for the invoice, parse it, and
/// return the customer's tax_number.
fn resolve_customer_tax_number(state: &AppState, invoice_id: &str) -> Result<String> {
    let ledger = Ledger::open(
        &*state.db_path,
        state.tenant.clone(),
        state
            .binary_hash
            .wait()
            .map_err(|e| anyhow!("binary hash: {e}"))?,
    )
    .with_context(|| format!("open audit ledger at {}", state.db_path.display()))?;
    let xml_path = find_draft_xml_path(&ledger, invoice_id)?;
    let input_json_path = sibling_input_json_path(&xml_path);
    let body = std::fs::read_to_string(&input_json_path).with_context(|| {
        format!(
            "read side-stored input.json at {} for invoice {}",
            input_json_path.display(),
            invoice_id
        )
    })?;
    let input: InvoiceInputJson = serde_json::from_str(&body).with_context(|| {
        format!(
            "parse side-stored input.json at {}",
            input_json_path.display()
        )
    })?;
    Ok(input.customer.tax_number)
}

fn resolve_invoice_xml_path(state: &AppState, invoice_id: &str) -> Result<PathBuf> {
    let ledger = Ledger::open(
        &*state.db_path,
        state.tenant.clone(),
        state
            .binary_hash
            .wait()
            .map_err(|e| anyhow!("binary hash: {e}"))?,
    )
    .with_context(|| format!("open audit ledger at {}", state.db_path.display()))?;
    find_draft_xml_path(&ledger, invoice_id)
}

fn find_draft_xml_path(ledger: &Ledger, invoice_id: &str) -> Result<PathBuf> {
    let entries = ledger
        .entries()
        .context("read audit-ledger entries to resolve InvoiceDraftCreated for email")?;
    for entry in entries.iter().rev() {
        if entry.kind != EventKind::InvoiceDraftCreated {
            continue;
        }
        let payload: audit_payloads::InvoiceDraftCreatedPayload =
            serde_json::from_slice(&entry.payload).with_context(|| {
                format!(
                    "InvoiceDraftCreated payload (seq {:?}) failed typed decode",
                    entry.seq
                )
            })?;
        if payload.invoice_id == invoice_id {
            let p = payload.nav_xml_path.ok_or_else(|| {
                anyhow!(
                    "InvoiceDraftCreated for {} has no nav_xml_path (pre-PR-18 entry)",
                    invoice_id
                )
            })?;
            return Ok(PathBuf::from(p));
        }
    }
    Err(anyhow!(
        "no InvoiceDraftCreated audit entry for invoice id {}",
        invoice_id
    ))
}

/// PR-44Œ∑ / session-60 ‚Äî wire-state mapper for the poll-ack response.
/// Mirrors the [`InvoiceTrace::derive_state`] ladder at the
/// poll-loop terminal level so the SPA can flip its state chip
/// without an extra `getInvoice` roundtrip.
fn poll_terminal_to_state(t: &poll_ack::PollAckTerminal) -> InvoiceState {
    match t {
        poll_ack::PollAckTerminal::Finalized => InvoiceState::Finalized,
        poll_ack::PollAckTerminal::Rejected => InvoiceState::Rejected,
        // Stuck variants leave the invoice at `Submitted` per ADR-0036
        // ¬ß3 ‚Äî the SPA renders the operator-visible diagnostic from
        // the `diagnostic` field and can prompt for retry / recovery.
        // The chip stays at `Submitted` because the underlying audit
        // trace still classifies the invoice as state-3 AwaitingAck;
        // a separate "SubmissionStuck" UI label would diverge from
        // the derive_state ladder.
        poll_ack::PollAckTerminal::StuckIntermediate { .. }
        | poll_ack::PollAckTerminal::StuckNonRetryable { .. }
        | poll_ack::PollAckTerminal::StuckAllAttemptsErrored { .. } => InvoiceState::Submitted,
    }
}

/// PR-44Œ∑ / session-60 ‚Äî surface the operator-visible diagnostic
/// (last-status string / NAV error message / etc.) on the wire so
/// the SPA can render it inline. `None` for the clean `Finalized`
/// arm.
fn poll_terminal_diagnostic(t: &poll_ack::PollAckTerminal) -> Option<String> {
    match t {
        poll_ack::PollAckTerminal::Finalized => None,
        poll_ack::PollAckTerminal::Rejected => Some(
            "NAV ack: ABORTED ‚Äî sequence slot is used-with-reason; issue a corrective new invoice"
                .to_string(),
        ),
        poll_ack::PollAckTerminal::StuckIntermediate { last_status } => Some(format!(
            "attempts exhausted with intermediate status {last_status}"
        )),
        poll_ack::PollAckTerminal::StuckNonRetryable { diagnostic } => {
            Some(format!("NAV non-retryable error: {diagnostic}"))
        }
        poll_ack::PollAckTerminal::StuckAllAttemptsErrored { diagnostic } => {
            Some(format!("all attempts errored, last: {diagnostic}"))
        }
    }
}

/// PR-44Œ∑ / session-60 ‚Äî per-invoice derived-state bundle the
/// mutation helpers consult for precondition checks. Carries the
/// derived state label (the same ladder `get_invoice_detail`
/// surfaces on the read path) AND the on-disk `nav_xml_path` the
/// helpers need for the wire-call payload, in one ledger walk.
struct DerivedStateForInvoice {
    state: InvoiceState,
    nav_xml_path: Option<std::path::PathBuf>,
}

/// PR-44Œ∑ / session-60 ‚Äî walk the audit ledger once and compute the
/// derived state + extract the most-recent `InvoiceDraftCreated`
/// payload's `nav_xml_path`. Mirrors the
/// `get_invoice_detail` walker shape so the read and mutation
/// surfaces agree on what "this invoice is in state X" means; a
/// regression that flipped one but not the other would surface here
/// loud per CLAUDE.md rule 12.
fn derive_state_for(
    state: &AppState,
    invoice_id: &str,
) -> std::result::Result<DerivedStateForInvoice, SubmitRouteError> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for serve mutation precondition")?;
    let entries = ledger
        .entries()
        .context("read audit ledger entries for precondition")?;

    let mut trace = InvoiceTrace::default();
    let mut nav_xml_path: Option<std::path::PathBuf> = None;
    let mut found_any = false;
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            if id == invoice_id {
                found_any = true;
                trace.merge_entry(entry, invoice_id);
                if entry.kind == EventKind::InvoiceDraftCreated {
                    if let Ok(parsed) = serde_json::from_slice::<
                        audit_payloads::InvoiceDraftCreatedPayload,
                    >(&entry.payload)
                    {
                        if let Some(path_str) = parsed.nav_xml_path {
                            nav_xml_path = Some(std::path::PathBuf::from(path_str));
                        }
                    }
                }
            }
        }
        if let Some(link) = extract_chain_link(entry) {
            if link.base_invoice_id == invoice_id {
                found_any = true;
                match link.kind {
                    EventKind::InvoiceStornoIssued => trace.is_storno_base = true,
                    EventKind::InvoiceModificationIssued => trace.is_amended_base = true,
                    _ => {}
                }
            }
        }
    }

    if !found_any {
        return Err(SubmitRouteError::NotFound(format!(
            "no audit-ledger entries for invoice id {invoice_id}"
        )));
    }
    Ok(DerivedStateForInvoice {
        state: trace.derive_state(),
        nav_xml_path,
    })
}

/// PR-44Œ∑ / session-60 ‚Äî extract the 8-digit supplier base tax
/// number from a NAV `<InvoiceData>` body. The CLI's
/// `submit-invoice --tax-number` accepts the dashed forms; the
/// NAV-emitted XML always carries the bare 8-digit base inside
/// `<supplierTaxNumber><common:taxpayerId>...</common:taxpayerId>`.
/// Server-derived so the SPA does not need to surface a tax-number
/// input on the operator-facing button.
///
/// Substring scan rather than a full XML parse per CLAUDE.md rule 2
/// (minimum code). Loud-fail on missing element OR a non-8-digit
/// payload per rule 12.
///
/// # PR-66 / session-87 ‚Äî `common:` namespace prefix
///
/// PR-50 / session-70 restructured the emitter to write the three
/// supplier/customer tax-number children with the `common:` prefix
/// (the NAV v3.0 `base` namespace) ‚Äî but this extractor was missed
/// and continued scanning for the bare-prefix form. The
/// substring-scan would then `None` at submit time, raising
/// `<supplierTaxNumber> missing <taxpayerId>` ‚Äî the misleading error
/// in session 87's live log on invoice 16 against NAV-test. The
/// emit was correct; this scan was wrong. The inline unit-test
/// fixtures below ALSO used the bare-prefix form so the tests
/// passed-but-lied (CLAUDE.md rule 9 ‚Äî tests verify intent, not
/// just behavior); they are now updated to the wire-real prefixed
/// form. The cross-module emit‚Üívalidate‚Üíextract pin in
/// `apps/aberp/tests/nav_xsd_validator_round_trip.rs` is the
/// load-bearing closer against future prefix divergence between
/// emitter and extractor.
///
/// The scan REQUIRES the `common:` prefix (no defensive accept of
/// the bare form) per CLAUDE.md rule 12 ‚Äî a future emit regression
/// that drops the prefix must surface here as a loud-fail rather
/// than be silently accepted.
fn parse_supplier_tax_number_from_xml(xml: &[u8]) -> Result<String> {
    let body = std::str::from_utf8(xml)
        .context("InvoiceData XML is not valid UTF-8 ‚Äî NAV requires UTF-8 per the v3.0 schema")?;
    let open = "<supplierTaxNumber>";
    let close = "</supplierTaxNumber>";
    let start = body
        .find(open)
        .ok_or_else(|| anyhow!("InvoiceData XML missing <supplierTaxNumber>"))?
        + open.len();
    let end = body[start..]
        .find(close)
        .ok_or_else(|| anyhow!("InvoiceData XML missing </supplierTaxNumber>"))?
        + start;
    let block = &body[start..end];
    let tag_open = "<common:taxpayerId>";
    let tag_close = "</common:taxpayerId>";
    let id_start = block.find(tag_open).ok_or_else(|| {
        anyhow!(
            "InvoiceData XML <supplierTaxNumber> missing <common:taxpayerId> \
             (NAV v3.0 base-namespace prefix required per PR-50; if the bare \
             form `<taxpayerId>` is present, the emitter dropped the prefix \
             ‚Äî fix nav_xml::write_supplier rather than relaxing this scan)"
        )
    })? + tag_open.len();
    let id_end = block[id_start..].find(tag_close).ok_or_else(|| {
        anyhow!("InvoiceData XML <supplierTaxNumber> missing </common:taxpayerId>")
    })? + id_start;
    let id = block[id_start..id_end].trim();
    if id.len() != 8 || !id.chars().all(|c| c.is_ascii_digit()) {
        return Err(anyhow!(
            "supplier <common:taxpayerId> value '{id}' is not 8 ASCII digits"
        ));
    }
    Ok(id.to_string())
}

/// Inspect the request's `Authorization` header against the expected
/// bearer token. Returns `Some(response)` if the request must be
/// rejected (no token, malformed token, mismatched token); returns
/// `None` if the request may proceed.
///
/// The `Option`-on-rejection shape (rather than `Result<(), Response>`)
/// avoids clippy's `result_large_err` lint ‚Äî `Response` is ~128 bytes
/// and `Result` carries it in both arms. Semantically clearer too:
/// `Some(resp)` reads as "here is the rejection response."
fn check_bearer_rejection(headers: &HeaderMap, expected: &str) -> Option<Response> {
    let auth = headers
        .get(axum::http::header::AUTHORIZATION)
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");
    if let Some(token) = auth.strip_prefix("Bearer ") {
        if constant_time_eq(token, expected) {
            return None;
        }
    }
    Some(
        (
            StatusCode::UNAUTHORIZED,
            Json(error_body("missing or invalid Bearer token".to_string())),
        )
            .into_response(),
    )
}

/// Constant-time string compare. A small loop is fine here ‚Äî the
/// strings are O(64) bytes. We never want to leak token length via a
/// fast `==` exit, so we walk the longer of the two and accumulate.
fn constant_time_eq(a: &str, b: &str) -> bool {
    let a = a.as_bytes();
    let b = b.as_bytes();
    if a.len() != b.len() {
        return false;
    }
    let mut diff = 0u8;
    for i in 0..a.len() {
        diff |= a[i] ^ b[i];
    }
    diff == 0
}

fn internal_error(context_label: &'static str, e: anyhow::Error) -> Response {
    tracing::error!(error = %format!("{e:#}"), "internal error in {}", context_label);
    (
        StatusCode::INTERNAL_SERVER_ERROR,
        Json(error_body("internal error".to_string())),
    )
        .into_response()
}

/// PR-58 / session-78 ‚Äî typed JSON body for NAV upstream-fault rejection
/// (HTTP-layer non-2xx returned by NAV's `tokenExchange`). Mapped to
/// HTTP 502 (Bad Gateway): the local server processed the request fine,
/// but the upstream NAV API rejected it. The four top-level fields
/// surface the operator-actionable diagnostic verbatim; the SPA's
/// invoice-detail modal renders `fault_code` + `fault_message`
/// prominently.
///
/// PR-59 / session-79 ‚Äî extended with `technical_validations`, the per-
/// rule list NAV emits inside repeated `<technicalValidationMessages>`
/// elements. For NAV's most common 400 (`fault_code=INVALID_REQUEST`)
/// this array is the ACTUAL diagnostic; the top-level is just the
/// generic wrapper. Wire shape is a flat array of typed
/// [`TechnicalValidationBody`] objects (snake_case fields match the
/// SPA's TS interface in `nav-upstream-fault.test.ts`).
#[derive(Serialize)]
struct NavUpstreamFaultBody {
    error: &'static str,
    status: u16,
    fault_code: Option<String>,
    fault_message: Option<String>,
    technical_validations: Vec<TechnicalValidationBody>,
    raw_body_preview: String,
}

/// PR-59 / session-79 ‚Äî wire-shape mirror of
/// [`aberp_nav_transport::operations::TechnicalValidation`]. A separate
/// struct (vs. deriving `Serialize` on the crate type) keeps the
/// nav-transport crate free of `serde` and lets the wire field names
/// be controlled here (snake_case to match the SPA's TS interface
/// `NavUpstreamFault.technical_validations`).
#[derive(Serialize)]
struct TechnicalValidationBody {
    result_code: Option<String>,
    error_code: Option<String>,
    message: Option<String>,
    tag: Option<String>,
}

impl From<TechnicalValidation> for TechnicalValidationBody {
    fn from(v: TechnicalValidation) -> Self {
        Self {
            result_code: v.result_code,
            error_code: v.error_code,
            message: v.message,
            tag: v.tag,
        }
    }
}

fn nav_upstream_fault_response(
    context_label: &'static str,
    status: u16,
    fault_code: Option<String>,
    fault_message: Option<String>,
    technical_validations: Vec<TechnicalValidation>,
    body_preview: String,
) -> Response {
    tracing::error!(
        nav_status = status,
        fault_code = ?fault_code,
        fault_message = ?fault_message,
        technical_validations_len = technical_validations.len(),
        body_preview = %body_preview,
        "NAV upstream fault in {}",
        context_label,
    );
    let technical_validations: Vec<TechnicalValidationBody> = technical_validations
        .into_iter()
        .map(TechnicalValidationBody::from)
        .collect();
    (
        StatusCode::BAD_GATEWAY,
        Json(NavUpstreamFaultBody {
            error: "nav_upstream_fault",
            status,
            fault_code,
            fault_message,
            technical_validations,
            raw_body_preview: body_preview,
        }),
    )
        .into_response()
}

#[derive(Serialize)]
struct ErrorBody {
    error: String,
}

fn error_body(error: String) -> ErrorBody {
    ErrorBody { error }
}

// ‚îÄ‚îÄ Read paths over billing DB + audit ledger ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

fn list_invoices(state: &AppState) -> Result<Vec<InvoiceListItem>> {
    // The audit ledger is the source of truth for "what invoices
    // exist." Walk every entry once; group by invoice_id; derive
    // state.
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for serve list")?;
    let entries = ledger.entries().context("read audit ledger entries")?;

    // PR-65 / session-86 ‚Äî sidecar map from invoice_id to the
    // `InvoiceDraftCreated` payload's `nav_xml_path`. Collected on
    // the same single walk so the items loop below can resolve each
    // invoice's side-store path (via `sibling_input_json_path`)
    // without a second ledger scan. Mirrors the parse posture in
    // `derive_state_for` so a future ADR that changes how nav_xml_path
    // is recorded surfaces in both places.
    let mut nav_xml_paths: std::collections::BTreeMap<String, std::path::PathBuf> =
        Default::default();
    let mut by_invoice: std::collections::BTreeMap<String, InvoiceTrace> = Default::default();
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            by_invoice
                .entry(id.clone())
                .or_default()
                .merge_entry(entry, &id);
            if entry.kind == EventKind::InvoiceDraftCreated {
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceDraftCreatedPayload,
                >(&entry.payload)
                {
                    if let Some(path_str) = parsed.nav_xml_path {
                        nav_xml_paths.insert(id.clone(), std::path::PathBuf::from(path_str));
                    }
                }
            }
        }
        // PR-23 / ADR-0036 ¬ß4 ‚Äî chain-link entries do not carry a
        // top-level `invoice_id` field; they carry
        // `storno_invoice_id` / `modification_invoice_id` (the
        // chain invoice's own id, which already enters `by_invoice`
        // via its own InvoiceSequenceReserved + InvoiceDraftCreated
        // pair) AND `base_invoice_id` (the chain link's anchor,
        // which is what flips the BASE invoice's trace into Storno
        // / Amended). Probe extracts both ids so this base-side
        // trace flip and the PR-32 chain-children walker (in
        // `get_invoice_detail`) share one parse per chain entry.
        if let Some(link) = extract_chain_link(entry) {
            // ADR-0049 ¬ßScreen render ‚Äî flag the storno CHILD's own row so
            // the SPA list negates its total. Do this before the base flip
            // so `child_invoice_id` is read before the move below.
            if link.kind == EventKind::InvoiceStornoIssued {
                by_invoice
                    .entry(link.child_invoice_id)
                    .or_default()
                    .is_storno_self = true;
            }
            let trace = by_invoice.entry(link.base_invoice_id).or_default();
            match link.kind {
                EventKind::InvoiceStornoIssued => trace.is_storno_base = true,
                EventKind::InvoiceModificationIssued => trace.is_amended_base = true,
                _ => {}
            }
        }
    }

    // Load billing details for each invoice id.
    let mut items: Vec<InvoiceListItem> = Vec::new();
    let mut conn = Connection::open(&*state.db_path)
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    for (id, trace) in by_invoice {
        let row = match read_invoice_row(&mut conn, &id)? {
            Some(row) => row,
            None => continue, // ledger has it but billing row gone ‚Äî skip silently
        };
        let buyer_name = nav_xml_paths
            .get(&id)
            .and_then(|p| read_buyer_name_from_side_store(p));
        let payment = trace.payment.clone().map(PaymentRecordSummary::from);
        items.push(InvoiceListItem {
            invoice_id: id,
            sequence_number: row.ready_invoice.sequence_number,
            fiscal_year: row.ready_invoice.fiscal_year,
            state: trace.derive_state(),
            total_gross: row.ready_invoice.total_gross().map(|h| h.as_i64()),
            has_chain_children: trace.is_storno_base || trace.is_amended_base,
            is_storno: trace.is_storno_self,
            currency: row.currency_metadata.currency,
            buyer_name,
            payment,
            // PR-73 / ADR-0040 ¬ßaddendum ‚Äî bank-account snapshot on the
            // list row. `None` for pre-PR-73 / CLI-issued rows.
            bank_account: row
                .bank_snapshot
                .clone()
                .map(BankAccountSnapshotResponse::from_typed),
        });
    }
    Ok(items)
}

/// PR-65 / session-86 ‚Äî best-effort read of the side-stored
/// [`InvoiceInputJson`] alongside a NAV-XML path, returning the
/// `customer.name` field for the SPA's Partner column. Returns
/// `None` for any failure (missing file, unreadable, malformed
/// JSON, blank name) ‚Äî the list endpoint must not loud-fail when
/// the read-side enrichment misses, since the side-store is only
/// present for PR-47Œ±+ SPA-issued invoices (CLI-issued invoices
/// and pre-PR-47Œ± SPA-issued invoices never wrote one). Pinned by
/// `read_buyer_name_from_side_store_round_trip`.
fn read_buyer_name_from_side_store(nav_xml_path: &std::path::Path) -> Option<String> {
    let path = sibling_input_json_path(nav_xml_path);
    let bytes = std::fs::read(&path).ok()?;
    let parsed: issue_invoice::InvoiceInputJson = serde_json::from_slice(&bytes).ok()?;
    let trimmed = parsed.customer.name.trim();
    if trimmed.is_empty() {
        None
    } else {
        Some(trimmed.to_string())
    }
}

fn get_invoice_detail(state: &AppState, invoice_id: &str) -> Result<Option<InvoiceDetailResponse>> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for serve detail")?;
    let entries = ledger.entries().context("read audit ledger entries")?;

    let mut trace = InvoiceTrace::default();
    let mut audit_entries: Vec<AuditEntryView> = Vec::new();
    let mut chain_children: Vec<ChainChildView> = Vec::new();
    let mut found_any = false;
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            if id == invoice_id {
                found_any = true;
                trace.merge_entry(entry, invoice_id);
                audit_entries.push(audit_view_of(entry));
            }
        }
        // PR-23 / ADR-0036 ¬ß4 ‚Äî chain-link entries: flip the
        // base's trace into Storno / Amended. Detail view is
        // queried by id, so we only flip when this id IS the
        // base. The chain-link entry itself does NOT appear in
        // `audit_entries` for the base's detail view ‚Äî those
        // entries belong to the storno / modification invoice's
        // own audit lineage; the base's lineage references them
        // only via the derived state label per ADR-0009 ¬ß2.
        //
        // PR-32 / session-36 ‚Äî same pass also collects the
        // chain CHILD's id into `chain_children` so the detail
        // modal can list "WHICH children" alongside the badge's
        // "has children." Ordering is ledger-walk order
        // (insertion order into `Vec`), which is monotonically
        // increasing seq per ADR-0008 ‚Äî operator-meaningful as
        // "chain entries in the order they were issued."
        if let Some(link) = extract_chain_link(entry) {
            if link.base_invoice_id == invoice_id {
                found_any = true;
                match link.kind {
                    EventKind::InvoiceStornoIssued => {
                        trace.is_storno_base = true;
                        chain_children.push(ChainChildView {
                            kind: ChainChildKind::Storno,
                            invoice_id: link.child_invoice_id,
                            modification_index: link.modification_index,
                        });
                    }
                    EventKind::InvoiceModificationIssued => {
                        trace.is_amended_base = true;
                        chain_children.push(ChainChildView {
                            kind: ChainChildKind::Amended,
                            invoice_id: link.child_invoice_id,
                            modification_index: link.modification_index,
                        });
                    }
                    _ => {}
                }
            } else if link.kind == EventKind::InvoiceStornoIssued
                && link.child_invoice_id == invoice_id
            {
                // ADR-0049 ¬ßScreen render ‚Äî this invoice IS the storno.
                // The `InvoiceStornoIssued` payload carries no top-level
                // `invoice_id`, so `extract_invoice_id` never attributes
                // it to the storno's own audit lineage; this chain-link
                // walk is the only place the storno child's id surfaces.
                trace.is_storno_self = true;
                found_any = true;
            }
        }
    }

    let mut conn = Connection::open(&*state.db_path)
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    let billing = read_invoice_row(&mut conn, invoice_id)?;

    if !found_any && billing.is_none() {
        return Ok(None);
    }

    // PR-44Œµ / session-53 ‚Äî split the billing read into the four
    // non-currency fields the prior wire shape carried plus the
    // five currency-aware fields (`currency` always present;
    // exchange-rate + source + date + huf_equivalent only on the
    // non-HUF branch). When the billing row is gone but the ledger
    // remembers the invoice (the rare `Unknown`-derived branch), we
    // default `currency` to `Currency::Huf` so the wire shape stays
    // valid; the four rate fields stay `None` because there is no
    // metadata to surface.
    let (
        sequence_number,
        fiscal_year,
        total_gross,
        currency_metadata,
        bank_snapshot,
        invoice_note,
        line_notes,
        invoice_dates,
    ) = match billing {
        Some(row) => {
            // PR-82 ‚Äî assemble the per-line notes view by walking
            // `row.ready_invoice.lines` (which carries each line's
            // `description` + `note` via the post-PR-82
            // `load_invoice` read). Filter out unannotated lines so
            // the SPA renderer can iterate the array directly
            // without per-row None checks.
            let line_notes_view: Vec<LineNoteView> = row
                .ready_invoice
                .lines
                .iter()
                .enumerate()
                .filter_map(|(idx, line)| {
                    let note_text = line.note.as_ref()?.trim();
                    if note_text.is_empty() {
                        return None;
                    }
                    Some(LineNoteView {
                        ordinal: idx as u32,
                        description: line.description.clone(),
                        note: note_text.to_string(),
                    })
                })
                .collect();
            // PR-99 Item 5 ‚Äî three dates surfaced to the detail wire.
            // `ready_invoice.issue_date` is OffsetDateTime; the other
            // two are `Date`. All three render as canonical YYYY-MM-DD
            // for the SPA (the SPA's renderer reformats to the
            // operator's locale display form).
            let date_fmt = ::time::macros::format_description!("[year]-[month]-[day]");
            let issue_date = row.ready_invoice.issue_date.date().format(date_fmt).ok();
            let payment_deadline = row.ready_invoice.payment_deadline.format(date_fmt).ok();
            let delivery_date = row.ready_invoice.delivery_date.format(date_fmt).ok();
            (
                row.ready_invoice.sequence_number,
                row.ready_invoice.fiscal_year,
                row.ready_invoice.total_gross().map(|h| h.as_i64()),
                row.currency_metadata,
                row.bank_snapshot,
                row.invoice_note,
                line_notes_view,
                (issue_date, payment_deadline, delivery_date),
            )
        }
        None => (
            0,
            0,
            None,
            InvoiceCurrencyMetadata {
                currency: Currency::Huf,
                exchange_rate: None,
                exchange_rate_source: None,
                exchange_rate_date: None,
                huf_equivalent_total: None,
            },
            None,
            None,
            Vec::new(),
            (None, None, None),
        ),
    };
    // PR-33 / session-37 ‚Äî typed wire emit of the latest NAV ack
    // for this invoice. `trace.last_ack_status` carries the raw
    // persisted string from `InvoiceAckStatusPayload.ack_status`;
    // parse it to the four-valued `AckStatus` enum at the wire
    // boundary. Unknown strings fall through to `None` (the audit-
    // entries drill-down still exposes the raw value).
    let last_ack_status = trace.last_ack_status.as_deref().and_then(parse_ack_status);
    let payment = trace.payment.clone().map(PaymentRecordSummary::from);
    Ok(Some(InvoiceDetailResponse {
        invoice_id: invoice_id.to_string(),
        sequence_number,
        fiscal_year,
        state: trace.derive_state(),
        total_gross,
        is_storno: trace.is_storno_self,
        audit_entries,
        chain_children,
        last_ack_status,
        currency: currency_metadata.currency,
        exchange_rate: currency_metadata.exchange_rate,
        exchange_rate_source: currency_metadata.exchange_rate_source,
        exchange_rate_date: currency_metadata.exchange_rate_date,
        huf_equivalent_total: currency_metadata.huf_equivalent_total,
        payment,
        // PR-73 / ADR-0040 ¬ßaddendum ‚Äî bank-account snapshot for the
        // SPA's "Pay to" sub-section. `null` for pre-PR-73 / CLI rows.
        bank_account: bank_snapshot.map(BankAccountSnapshotResponse::from_typed),
        // PR-82 ‚Äî buyer-facing notes (global + per-line). NEVER on
        // the NAV XML wire (see ADR-0042); the SPA's
        // `InvoiceDetail.svelte` renders them so the operator can
        // preview what the buyer will see on the printed PDF.
        invoice_note,
        line_notes,
        // PR-99 Item 5 ‚Äî three dates rendered on the detail meta-grid.
        issue_date: invoice_dates.0,
        payment_deadline: invoice_dates.1,
        delivery_date: invoice_dates.2,
    }))
}

fn get_audit_for_invoice(state: &AppState, invoice_id: &str) -> Result<Vec<AuditEntryView>> {
    let binary_hash = state
        .binary_hash
        .wait()
        .context("await background binary hash compute")?;
    let ledger = Ledger::open(&*state.db_path, state.tenant.clone(), binary_hash)
        .context("open audit ledger for serve audit")?;
    let entries = ledger.entries().context("read audit ledger entries")?;
    let mut out = Vec::new();
    for entry in &entries {
        if let Some(id) = extract_invoice_id(entry) {
            if id == invoice_id {
                out.push(audit_view_of(entry));
            }
        }
    }
    Ok(out)
}

fn audit_view_of(entry: &Entry) -> AuditEntryView {
    // PR-27 ‚Äî the full typed payload as raw JSON. Every
    // `audit_payloads::*` type serialises via `serde_json::to_vec`
    // (F9 ‚Äî closed in PR-6.1) so the bytes always parse cleanly;
    // a malformed payload falls back to `Null` rather than
    // panicking, so a corrupted entry is inspector-visible per
    // CLAUDE.md rule 12.
    let mut payload = serde_json::from_slice::<serde_json::Value>(&entry.payload)
        .unwrap_or(serde_json::Value::Null);
    // PR-76 ‚Äî when the entry is an `InvoiceAckStatus`, parse the
    // `<technicalValidationMessages>` array out of the verbatim NAV
    // ack body (`response_xml`) and graft it onto the payload as a
    // sibling field. The SPA's `invoice-timeline.ts` renders the array
    // inline under the ack node so an operator staring at "Rejected"
    // in the state chip sees WHY without digging through logs. Only
    // ABORTED acks actually carry validation messages; SAVED /
    // PROCESSING / RECEIVED parse to an empty array, which the SPA
    // renders as nothing additional ‚Äî the field name is the same
    // either way so the wire shape stays uniform.
    if entry.kind == EventKind::InvoiceAckStatus {
        if let Some(messages) = parse_ack_technical_validations(&payload) {
            if let serde_json::Value::Object(ref mut map) = payload {
                map.insert(
                    "technical_validation_messages".to_string(),
                    serde_json::json!(messages
                        .into_iter()
                        .map(TechnicalValidationBody::from)
                        .collect::<Vec<_>>()),
                );
            }
        }
    }
    AuditEntryView {
        seq: entry.seq.as_u64(),
        kind: format!("{:?}", entry.kind),
        actor: entry.actor.user_id.clone(),
        // ADR-0008 ¬ß"Entry shape" names two timestamps: `time_wall`
        // (RFC3339, operator-readable) and `time_mono` (monotonic
        // nanos since process start, drift-immune). The serve view
        // wants the operator-readable form.
        occurred_at: entry.time_wall.to_string(),
        // PR-26 ‚Äî reuse the existing chain-link probe. The probe
        // already short-circuits on kind first per ADR-0036 ¬ß4, so
        // the cost is bounded for non-chain entries. PR-32 widened
        // the probe's return to also carry the chain child id; the
        // audit-entry view consumes only the base id here.
        chain_base_invoice_id: extract_chain_link(entry).map(|link| link.base_invoice_id),
        payload,
    }
}

/// PR-76 ‚Äî extract the `response_xml` bytes from an
/// [`audit_payloads::InvoiceAckStatusPayload`] JSON Value and parse the
/// per-rule `<technicalValidationMessages>` array out of them. Returns
/// `None` when the payload shape does not match (corrupt entry ‚Äî the
/// caller leaves the payload unchanged so the inspector-visible
/// fall-back posture from `audit_view_of` carries over).
fn parse_ack_technical_validations(
    payload: &serde_json::Value,
) -> Option<Vec<TechnicalValidation>> {
    let bytes_arr = payload.get("response_xml")?.as_array()?;
    let mut bytes: Vec<u8> = Vec::with_capacity(bytes_arr.len());
    for v in bytes_arr {
        let n = v.as_u64()?;
        if n > 0xFF {
            return None;
        }
        bytes.push(n as u8);
    }
    find_all_technical_validations(&bytes).ok()
}

/// PR-44Œµ / session-53 ‚Äî currency-aware billing read bundle.
///
/// The pre-PR-44Œµ `read_invoice_row` returned just
/// `(ReadyInvoice, IdempotencyKey)`. PR-44Œµ threads the five
/// PR-44Œ≥-added DuckDB columns (`currency`, `exchange_rate`,
/// `exchange_rate_source`, `exchange_rate_date`,
/// `huf_equivalent_total`) into the same read so the list-row +
/// detail-modal wire surfaces (`InvoiceListItem` /
/// `InvoiceDetailResponse`) can render currency + rate metadata
/// without a second DB hit. The currency lookup runs inside the
/// same `Transaction` as `load_ready_invoice_by_id`, keeping the
/// per-invoice read at one open-tx-commit per the existing serve
/// posture.
///
/// The `IdempotencyKey` is preserved on the bundle even though no
/// PR-44Œµ caller consumes it ‚Äî `read_invoice_row` is a shared
/// helper between `list_invoices` and `get_invoice_detail`, and
/// future callers (chain-currency-match diagnostics, retry-side
/// idempotency assertions) may want the key. Dropping it would be
/// a regression on the pre-PR-44Œµ surface; keeping it is zero
/// runtime cost (the value was read inside `load_ready_invoice_by_id`
/// regardless).
struct ReadInvoiceRow {
    ready_invoice: ReadyInvoice,
    #[allow(dead_code)]
    idempotency_key: billing::IdempotencyKey,
    currency_metadata: InvoiceCurrencyMetadata,
    /// PR-73 / ADR-0040 ¬ßaddendum ‚Äî typed bank-account snapshot loaded
    /// from the five `bank_account_*` invoice columns. `None` for pre-
    /// PR-73 / CLI-issued rows (those rows have NULL across all five
    /// columns; `InvoiceBankSnapshot.into_typed()` returns `None`).
    bank_snapshot: Option<aberp_billing::BankAccountSnapshot>,
    /// PR-82 ‚Äî buyer-facing per-invoice note ("Megjegyz√©s") loaded
    /// from the `invoice.invoice_note` column. `None` for invoices the
    /// operator did not annotate AND for pre-PR-82 rows (the migration
    /// added the column without backfill). Per-line notes ride on
    /// `ready_invoice.lines[i].note` via the billing crate's
    /// `load_invoice` read.
    invoice_note: Option<String>,
}

/// Scoped read tx + billing lookup; returns None if the row is not
/// present.
fn read_invoice_row(conn: &mut Connection, invoice_id: &str) -> Result<Option<ReadInvoiceRow>> {
    let tx = conn
        .transaction()
        .context("begin read transaction for invoice lookup (serve)")?;
    let pair = billing::load_ready_invoice_by_id(&tx, invoice_id)
        .context("billing::load_ready_invoice_by_id (serve)")?;
    let pair = match pair {
        Some(p) => p,
        None => {
            tx.commit().context("commit read transaction (serve)")?;
            return Ok(None);
        }
    };
    let currency_metadata = load_invoice_currency_metadata_in_tx(&tx, invoice_id)
        .context("load_invoice_currency_metadata_in_tx (serve)")?;
    // PR-73 / ADR-0040 ¬ßaddendum ‚Äî read the five bank-snapshot columns
    // in the same tx so list + detail share one read trip.
    let bank_snapshot = load_invoice_bank_snapshot_in_tx(&tx, invoice_id)
        .context("load_invoice_bank_snapshot_in_tx (serve)")?
        .into_typed();
    // PR-82 ‚Äî read the buyer-facing per-invoice note in the SAME tx so
    // the list + detail wire surfaces share one read trip with the rest
    // of the row's data. Per-line notes already round-trip through
    // `pair.0.lines[i].note` because `load_ready_invoice_by_id` selects
    // the column.
    let invoice_note = billing::load_invoice_note_in_tx(&tx, invoice_id)
        .context("billing::load_invoice_note_in_tx (serve)")?;
    tx.commit().context("commit read transaction (serve)")?;
    Ok(Some(ReadInvoiceRow {
        ready_invoice: pair.0,
        idempotency_key: pair.1,
        currency_metadata,
        bank_snapshot,
        invoice_note,
    }))
}

// ‚îÄ‚îÄ State derivation from the audit-ledger trace ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

/// Per-invoice accumulator for the audit-ledger walk.
///
/// PR-23 / ADR-0036 ¬ß2 extends this with four new fact-bits over
/// the pre-PR-23 five-bit shape (`has_draft`,
/// `has_submission_response`, `has_retry_requested`,
/// `has_marked_abandoned`, `last_ack_status`):
///
///   - `has_attempt` ‚Äî `InvoiceSubmissionAttempt` exists for this
///     invoice (PR-19 / ADR-0032 ¬ß4). Drives the `Pending` /
///     `PendingNavExists` labels at the state-2 ladder branch.
///   - `latest_response_is_recovered` ‚Äî the most-recent
///     `InvoiceSubmissionResponse`'s `response_xml` carries
///     `<QueryInvoiceDataResponse>` bytes per ADR-0034 ¬ß4. Drives
///     the `Recovered` vs `Submitted` distinction at the state-3
///     ladder branch.
///   - `latest_check_outcome` ‚Äî the most-recent
///     `InvoiceCheckPerformed`'s `outcome` field (PR-20 / ADR-0033
///     ¬ß6). Drives the `PendingNavExists` sub-label.
///   - `is_storno_base` / `is_amended_base` ‚Äî set by
///     [`extract_chain_link`] from
///     `InvoiceStornoIssuedPayload` / `InvoiceModificationIssuedPayload`
///     entries whose `base_invoice_id` equals this invoice's id
///     (PR-10 / ADR-0023, PR-11 / ADR-0024). Drives the `Storno` /
///     `Amended` labels.
#[derive(Default)]
struct InvoiceTrace {
    has_draft: bool,
    /// PR-23 / ADR-0036 ¬ß2 ‚Äî state-2 Pending evidence.
    has_attempt: bool,
    has_submission_response: bool,
    /// PR-23 / ADR-0036 ¬ß5 ‚Äî most-recent Response's
    /// recovered-or-original discriminator.
    latest_response_is_recovered: bool,
    has_retry_requested: bool,
    has_marked_abandoned: bool,
    last_ack_status: Option<String>,
    /// PR-23 / ADR-0036 ¬ß6 ‚Äî most-recent Layer-2 check outcome.
    /// Values per ADR-0033 ¬ß2: `"exists"` / `"absent"` / `"failure"`.
    latest_check_outcome: Option<String>,
    /// PR-23 / ADR-0036 ¬ß4 ‚Äî base of an `InvoiceStornoIssued` chain
    /// entry. Set via [`extract_chain_link`].
    is_storno_base: bool,
    /// PR-23 / ADR-0036 ¬ß4 ‚Äî base of an `InvoiceModificationIssued`
    /// chain entry. Set via [`extract_chain_link`].
    is_amended_base: bool,
    /// ADR-0049 ¬ßScreen render (session 156) ‚Äî this invoice IS a storno
    /// (the chain CHILD, not the base). Set via [`extract_chain_link`]
    /// when an `InvoiceStornoIssued` entry's `storno_invoice_id`
    /// (`child_invoice_id`) equals this invoice's id. The billing tables
    /// store the storno line with a POSITIVE `unit_price` (negation lives
    /// only in the NAV-XML render path), so the SPA needs this flag to
    /// negate the displayed total ‚Äî matching the buyer-facing PDF, which
    /// parses the negated NAV XML. Does NOT change `derive_state` (the
    /// storno child's own NAV ladder is independent of being a storno).
    is_storno_self: bool,
    /// PR-70 / ADR-0039 ¬ß2 ‚Äî most-recent `InvoicePaymentRecorded`
    /// payload's operator-facing fields for the SPA's Paid chip.
    /// `Some(...)` when at least one payment entry exists for this
    /// invoice; the audit ledger is append-only so once `Some`,
    /// stays `Some`. Does NOT change `derive_state` ‚Äî paid-vs-unpaid
    /// is operational metadata, separate from the NAV regulatory
    /// ladder per ADR-0039 ¬ß3.
    payment: Option<PaymentRecord>,
}

impl InvoiceTrace {
    fn merge_entry(&mut self, entry: &Entry, invoice_id: &str) {
        match entry.kind {
            EventKind::InvoiceDraftCreated => self.has_draft = true,
            EventKind::InvoiceSubmissionAttempt => {
                // PR-23 / ADR-0036 ¬ß2 ‚Äî state-2 Pending evidence.
                // The cross-invoice contamination guard parses the
                // payload's `invoice_id` field; pre-PR-23 the
                // walker collapsed Attempt into the catch-all `_`
                // arm and the Pending classification was invisible
                // at the UI layer.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceSubmissionAttemptPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.has_attempt = true;
                    }
                }
            }
            EventKind::InvoiceSubmissionResponse => {
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceSubmissionResponsePayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.has_submission_response = true;
                        // PR-23 / ADR-0036 ¬ß5 ‚Äî mirror the
                        // verifier's A91 prefix-match: a response
                        // whose first ~512 bytes contain
                        // `QueryInvoiceDataResponse` was emitted
                        // by `recover-from-nav` per ADR-0034 ¬ß4.
                        // Walk is in seq order; the LAST Response
                        // wins ‚Äî `latest_response_is_recovered`
                        // is overwritten on each match.
                        self.latest_response_is_recovered =
                            is_recovered_response_xml(&parsed.response_xml);
                    }
                }
            }
            EventKind::InvoiceAckStatus => {
                if let Ok(parsed) = serde_json::from_slice::<audit_payloads::InvoiceAckStatusPayload>(
                    &entry.payload,
                ) {
                    if parsed.invoice_id == invoice_id {
                        self.last_ack_status = Some(parsed.ack_status);
                    }
                }
            }
            EventKind::InvoiceCheckPerformed => {
                // PR-23 / ADR-0036 ¬ß6 ‚Äî Layer-2 outcome. Mirrors
                // ADR-0033 ¬ß6's command-side informational-only
                // posture: stuck_precondition does NOT consult
                // these entries; derive_state surfaces them at the
                // label level to give the operator a separate
                // signal that recommends `recover-from-nav` over
                // `retry-submission`.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoiceCheckPerformedPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.latest_check_outcome = Some(parsed.outcome);
                    }
                }
            }
            EventKind::InvoiceRetryRequested => {
                self.has_retry_requested = true;
            }
            EventKind::InvoiceMarkedAbandoned => {
                self.has_marked_abandoned = true;
            }
            EventKind::InvoicePaymentRecorded => {
                // PR-70 / ADR-0039 ¬ß2 ‚Äî capture the operator-facing
                // payment fields onto the trace. Walk is in seq
                // order (oldest ‚Üí newest), so the last matching
                // entry wins ‚Äî defensive against a hypothetical
                // future "amend payment" PR that appends a fresh
                // entry without breaking the no-double-pay v1
                // invariant the route layer enforces.
                if let Ok(parsed) = serde_json::from_slice::<
                    audit_payloads::InvoicePaymentRecordedPayload,
                >(&entry.payload)
                {
                    if parsed.invoice_id == invoice_id {
                        self.payment = Some(PaymentRecord {
                            paid_at: parsed.paid_at,
                            amount_minor: parsed.amount_minor,
                            currency: parsed.currency,
                            method: parsed.method,
                            reference: parsed.reference,
                        });
                    }
                }
            }
            _ => {}
        }
    }

    /// Derive the ADR-0009 ¬ß2 typestate label from the accumulated
    /// trace. PR-23 / ADR-0036 ¬ß3 extends the pre-PR-23 six-label
    /// ladder to eleven labels with the priority ordering:
    ///
    /// ```text
    /// 1. Abandoned             (matches stuck_precondition step 1)
    /// 2. Storno                (chain-link evidence; ADR-0009 ¬ß2)
    /// 3. Amended               (chain-link evidence; ADR-0009 ¬ß2)
    /// 4. Finalized             (matches stuck_precondition AlreadyFinalized)
    /// 5. Rejected              (matches stuck_precondition AlreadyRejected)
    /// 6. Recovered             (sub-label of Submitted; ADR-0034 ¬ß4)
    /// 7. Submitted             (matches stuck_precondition AwaitingAck)
    /// 8. PendingNavExists      (sub-label of Pending; ADR-0033 ¬ß6)
    /// 9. Pending               (matches stuck_precondition Pending; ADR-0032 ¬ß4)
    /// 10. Ready                 (Draft entered the ledger; no submit yet)
    /// 11. Unknown               (no entries for this invoice)
    /// ```
    ///
    /// The mirror invariant per ADR-0036 ¬ß1: for every state both
    /// this ladder and `audit_query::stuck_precondition` can name,
    /// the two MUST agree. Drift is the failure mode the
    /// `derive_state_label_table_mirror` test pins loud per
    /// CLAUDE.md rule 12.
    fn derive_state(&self) -> InvoiceState {
        // 1. Terminal-by-operator-decision wins over everything.
        if self.has_marked_abandoned {
            return InvoiceState::Abandoned;
        }
        // 2-3. Chain-link terminal ‚Äî the base invoice's typestate
        //      transition per ADR-0009 ¬ß2. Storno and Amended are
        //      orthogonal (an invoice can be the base of both over
        //      its lifetime per ADR-0024 ¬ß7); the ladder picks
        //      Storno first if both are set. Operationally rare to
        //      see both on the same base; the audit-entries view
        //      exposes the full chain to the operator.
        if self.is_storno_base {
            return InvoiceState::Storno;
        }
        if self.is_amended_base {
            return InvoiceState::Amended;
        }
        // 4-5. Terminal-by-NAV from the ack status.
        match self.last_ack_status.as_deref() {
            Some("SAVED") => return InvoiceState::Finalized,
            Some("ABORTED") => return InvoiceState::Rejected,
            _ => {}
        }
        // 6-7. State-3: Response exists, no terminal ack, no
        //      abandon. The Recovered / Submitted sub-label split
        //      mirrors ADR-0034 ¬ß4's chain-walk-by-order posture
        //      at the byte level (response_xml root element prefix
        //      per ADR-0035 ¬ß4 / A91).
        if self.has_submission_response {
            if self.latest_response_is_recovered {
                return InvoiceState::Recovered;
            }
            return InvoiceState::Submitted;
        }
        // 8-9. State-2: Attempt exists, no Response, no abandon.
        //      The PendingNavExists / Pending sub-label split
        //      mirrors ADR-0033 ¬ß6's informational-only Layer-2
        //      posture at the UI level.
        if self.has_attempt {
            if matches!(self.latest_check_outcome.as_deref(), Some("exists")) {
                return InvoiceState::PendingNavExists;
            }
            return InvoiceState::Pending;
        }
        // 10. Pre-submission: Draft entered the ledger.
        if self.has_draft {
            return InvoiceState::Ready;
        }
        // 11. No entries for this invoice id.
        InvoiceState::Unknown
    }
}

/// PR-23 / ADR-0036 ¬ß5 ‚Äî recovered-Response discriminator.
///
/// Mirrors ADR-0035 ¬ß4 / A91's prefix-match local-name check at
/// the UI level: a NAV-emitted `response_xml` whose first ~512
/// bytes contain the substring `QueryInvoiceDataResponse` was
/// emitted by `recover-from-nav` per ADR-0034 ¬ß4 (which reuses
/// the existing `InvoiceSubmissionResponsePayload` shape with
/// `<QueryInvoiceDataResponse>` bytes rather than
/// `<ManageInvoiceResponse>`).
///
/// 512-byte window: the root element appears in the first ~200
/// bytes on every NAV-emitted body (XML prolog + optional
/// whitespace + optional namespace-prefixed open tag). Bounded so
/// a malformed or oversized payload doesn't scan the whole body.
///
/// Substring scan rather than exact prefix-match per
/// ADR-0036 ¬ß"Adversarial review" #2 + CLAUDE.md rule 2: the
/// dependency on quick-xml or the verifier crate's prefix-match
/// helper is not justified for the UI label split. A future PR
/// can upgrade the discriminator additively if operational
/// evidence surfaces.
fn is_recovered_response_xml(response_xml: &[u8]) -> bool {
    let window = &response_xml[..response_xml.len().min(512)];
    window
        .windows(NEEDLE_QUERY_INVOICE_DATA_RESPONSE.len())
        .any(|w| w == NEEDLE_QUERY_INVOICE_DATA_RESPONSE)
}

/// The substring scanned by [`is_recovered_response_xml`].
/// Module-level constant so the discriminator's exact bytes are
/// auditable in one place per ADR-0036 ¬ß5.
const NEEDLE_QUERY_INVOICE_DATA_RESPONSE: &[u8] = b"QueryInvoiceDataResponse";

/// PR-23 / ADR-0036 ¬ß4 ‚Äî chain-link detection probe.
///
/// `InvoiceStornoIssuedPayload` and
/// `InvoiceModificationIssuedPayload` do NOT carry a top-level
/// `invoice_id` field; the existing [`extract_invoice_id`] probe
/// returns `None` for these entries. This sister probe walks the
/// per-payload chain-link fields and returns the chain entry's
/// own invoice id (`storno_invoice_id` / `modification_invoice_id`)
/// alongside the `base_invoice_id` so the BASE invoice's trace
/// can be flipped into Storno / Amended at the list-and-detail
/// walker level AND the base's detail view can list its children
/// (PR-32 / Option T).
///
/// PR-32 / session-36 ‚Äî extended in place rather than forked into
/// a sister probe per reuse-over-fork (A106). The added field
/// `child_invoice_id` is the chain entry's own id, parsed from
/// whichever payload-specific field carries it; every call site
/// that previously consumed `(kind, base_id)` is updated to
/// destructure the [`ChainLink`] struct.
///
/// Returns `None` for every other `EventKind` (the typed probe
/// would fail to decode on the wrong payload shape; we
/// short-circuit on kind match first to keep the cost bounded).
fn extract_chain_link(entry: &Entry) -> Option<ChainLink> {
    #[derive(Deserialize)]
    struct StornoProbe {
        storno_invoice_id: String,
        base_invoice_id: String,
        modification_index: u32,
    }
    #[derive(Deserialize)]
    struct ModificationProbe {
        modification_invoice_id: String,
        base_invoice_id: String,
        modification_index: u32,
    }
    match entry.kind {
        EventKind::InvoiceStornoIssued => {
            let probe: StornoProbe = serde_json::from_slice(&entry.payload).ok()?;
            Some(ChainLink {
                kind: entry.kind.clone(),
                child_invoice_id: probe.storno_invoice_id,
                base_invoice_id: probe.base_invoice_id,
                modification_index: probe.modification_index,
            })
        }
        EventKind::InvoiceModificationIssued => {
            let probe: ModificationProbe = serde_json::from_slice(&entry.payload).ok()?;
            Some(ChainLink {
                kind: entry.kind.clone(),
                child_invoice_id: probe.modification_invoice_id,
                base_invoice_id: probe.base_invoice_id,
                modification_index: probe.modification_index,
            })
        }
        _ => None,
    }
}

/// PR-32 / session-36 ‚Äî chain-link probe return shape.
///
/// Carries the chain-link identifiers needed by every consumer:
///   - `child_invoice_id` ‚Äî the chain entry's OWN invoice id (i.e.,
///     the storno or modification invoice itself).
///   - `base_invoice_id` ‚Äî the BASE invoice the chain entry is
///     attached to.
///   - `modification_index` ‚Äî the per-base chain index allocated by
///     `next_modification_index_in_tx` in `issue_storno.rs` /
///     `issue_modification.rs` (PR-41 / session-45 ‚Äî surfaced on the
///     chain-children list per Option W). Shared name space across
///     stornos and modifications against the same base; the persisted
///     payload field is the same `modification_index: u32` on both
///     `InvoiceStornoIssuedPayload` and `InvoiceModificationIssuedPayload`.
///
/// Plus `kind`, the originating `EventKind` discriminant so callers
/// can match `InvoiceStornoIssued` / `InvoiceModificationIssued`
/// without re-parsing the payload.
struct ChainLink {
    kind: EventKind,
    child_invoice_id: String,
    base_invoice_id: String,
    modification_index: u32,
}

/// Extract the `invoice_id` field (if any) from an audit-ledger entry's
/// typed payload. Returns None for entries that don't carry an
/// invoice_id at all (none of the v3.0 payloads).
fn extract_invoice_id(entry: &Entry) -> Option<String> {
    // All current typed payloads carry an `invoice_id: String` field.
    // We parse permissively ‚Äî a payload that fails to decode is
    // skipped rather than blowing up the entire serve view.
    #[derive(Deserialize)]
    struct Probe {
        invoice_id: String,
    }
    let probe: Probe = serde_json::from_slice(&entry.payload).ok()?;
    Some(probe.invoice_id)
}

